INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('1910f6bc-5a6a-513d-a3f0-bf70f71213a0', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'accessible', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/əkˈsɛs.ə.bəl/', 'audio/accessible.mp3', 'Easy of access or approach.', 'an accessible town or mountain', 'Society & Culture', 'có thể tiếp cận', 'Dễ dàng tiếp cận hoặc đến gần.', 'một thị trấn hoặc ngọn núi có thể tiếp cận được'),
    ('b2f203ff-9766-591d-948e-ed6888e70e7e', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'aftermath', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈæf.təˌmæθ/', 'audio/aftermath.mp3', 'A second mowing; the grass which grows after the first crop of hay in the same season.', 'In contrast to most projections of the aftermath of nuclear war, in this there is no rioting or looting.', 'Society & Culture', 'hậu quả', 'Việc cắt cỏ lần thứ hai; cỏ mọc sau vụ cắt cỏ khô đầu tiên trong cùng mùa.', 'Trái ngược với hầu hết dự đoán về hậu quả của chiến tranh hạt nhân, trong trường hợp này không có bạo loạn hay cướp bóc.'),
    ('3d72512d-69ae-5387-bb3d-72dba39a7204', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'alliance', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/əˈlaɪ.əns/', 'audio/alliance.mp3', 'The state of being allied.', 'matrimonial alliances; an alliance between church and state, or between two countries', 'Society & Culture', 'liên minh, đồng minh', 'Trạng thái liên kết với nhau.', 'liên minh hôn nhân; một liên minh giữa nhà thờ và nhà nước, hoặc giữa hai quốc gia'),
    ('a55c3f99-3bb6-5c58-8230-8e20263f1d0f', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'angel', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈeɪn.dʒəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/angel-uk.mp3', 'An incorporeal and sometimes divine messenger from a deity, or other divine entity, often depicted in art as a youthful winged figure in flowing robes.', 'Thanks for making me breakfast in bed, you little angel.', 'Society & Culture', 'thiên thần', 'Một sứ giả phi vật chất và đôi khi là thần thánh từ một vị thần, hoặc thực thể thần thánh khác, thường được mô tả trong nghệ thuật như một nhân vật có cánh trẻ trung trong bộ áo choàng dài.', 'Cảm ơn vì đã làm bữa sáng cho tôi trên giường, cô bé thiên thần.'),
    ('fb42f5c6-b504-50fb-9a18-37da203262b2', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'anonymous', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/əˈnɒnəməs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/anonymous-us.mp3', 'Lacking a name; not named, for example an animal not assigned to any species.', 'an anonymous pamphlet', 'Society & Culture', 'vô danh, ẩn danh', 'Thiếu tên; không được đặt tên, ví dụ một con vật không được phân loại vào bất kỳ loài nào.', 'một cuốn sách nhỏ ẩn danh'),
    ('e79f2dca-d50e-5d64-a5e6-8b2c2f3f8778', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'banner', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈbænə/', 'audio/banner.mp3', 'A flag or standard used by a military commander, monarch or nation.', 'The mayor hung a banner across Main Street to commemorate the town''s 100th anniversary.', 'Society & Culture', 'biểu ngữ', 'Một lá cờ hoặc tiêu chuẩn được sử dụng bởi một chỉ huy quân sự, quân chủ hoặc quốc gia.', 'Thị trưởng treo một biểu ngữ băng ngang Phố Chính để kỷ niệm 100 năm thành lập thị trấn.'),
    ('c4837828-8780-5151-8539-e77e0842e461', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'blessing', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈblɛs.ɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/blessing-us.mp3', 'To make something holy by religious rite, sanctify.', 'We will not proceed without the executive director''s blessing.', 'Society & Culture', 'phước lành', 'Làm cho một thứ gì đó trở nên linh thiêng bằng nghi thức tôn giáo, thánh hóa.', 'Chúng tôi sẽ không tiến hành nếu không có sự chúc phúc của giám đốc điều hành.'),
    ('77767b66-ad37-5f3c-b416-e9977f09c77f', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'charm', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/tʃɑːm/', 'audio/charm.mp3', 'An object, act or words believed to have magic power (usually carries a positive connotation).', 'It works like a charm.', 'Society & Culture', 'bùa, sức quyến rũ', 'Một vật thể, hành động hoặc lời nói được cho là có sức mạnh ma thuật (thường mang ý nghĩa tích cực).', 'Nó hoạt động hiệu quả như một bùa may mắn.'),
