    ('0b9b298b-7055-52a3-b551-6486846821a4', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'escalate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈɛs.kə.leɪt/', 'audio/escalate.mp3', 'To increase (something) in extent or intensity; to intensify or step up.', 'The shooting escalated the existing hostility.', 'Society & Culture', 'leo thang', 'Làm tăng (cái gì đó) về mức độ hoặc cường độ; tăng cường hoặc đẩy mạnh.', 'Vụ nổ súng đã leo thang sự thù địch vốn có.'),
    ('4d923319-ec03-526c-afc3-8651c6ebd793', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'eternal', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ɪˈtɜːnəl/', 'audio/eternal.mp3', 'One who lives forever; an immortal.', 'some eternal villain', 'Society & Culture', 'vĩnh cửu', 'Người sống mãi mãi; một người bất tử.', 'một số kẻ phản diện vĩnh cửu'),
    ('f140093d-5d7e-55e4-829d-21f5ab0523cc', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'evacuate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ɪˈvæk.ju.eɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/evacuate-uk.mp3', 'To leave or withdraw from; to quit; to retire from', 'The firefighters told us to evacuate the area as the flames approached.', 'Society & Culture', 'sơ tán', 'Rời đi hoặc rút lui khỏi; từ bỏ; rút lui', 'Lính cứu hỏa bảo chúng tôi sơ tán khỏi khu vực khi ngọn lửa tiến đến.'),
