    ('f699b1c1-f94b-5df6-ba16-68bec9469555', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'fate', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/feɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fate-us.mp3', 'The presumed cause, force, principle, or divine will that predetermines events.', 'Accept your fate.', 'Society & Culture', 'số phận, định mệnh', 'Nguyên nhân, lực lượng, nguyên tắc, hoặc ý chí thần thánh được cho là định trước các sự kiện.', 'Hãy chấp nhận số phận của bạn.'),
    ('4f2ab2f5-6918-5f0f-8fa0-0c738304a82e', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'funeral', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈfjuːnəɹəl/', 'audio/funeral.mp3', 'A ceremony to honour and remember a deceased person. Often distinguished from a memorial service by the presence of the body of the deceased.', 'Many mourners turned up at the local artist''s funeral to pay homage.', 'Society & Culture', 'đám tang', 'Một nghi lễ để tôn vinh và tưởng nhớ một người đã khuất. Thường được phân biệt với lễ tưởng niệm bởi sự hiện diện của thi thể người quá cố.', 'Nhiều người thương tiếc đã đến dự đám tang của nghệ sĩ địa phương để bày tỏ lòng tôn kính.'),
    ('57127d8f-2b26-59c9-aceb-2521dafc328b', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'gathering', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈɡæ.ðə.ɹɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/gathering-us.mp3', 'A meeting or get-together; a party or social function.', 'I met her at a gathering of engineers and scientists.', 'Society & Culture', 'tụ họp', 'Một cuộc họp mặt hay tụ tập; một bữa tiệc hoặc sự kiện xã hội.', 'Tôi gặp cô ấy tại một buổi tụ họp của các kỹ sư và nhà khoa học.'),
    ('ad22667a-9b7f-5451-9fc2-fbeddaa2f878', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'heritage', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈhɛɹɪtɪd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/heritage-us.mp3', 'An inheritance; property that may be inherited.', 'The university requires heritage Spanish students to enroll in a specially designed Spanish program not available to non-heritage students.', 'Society & Culture', 'di sản', 'Một tài sản thừa kế; tài sản có thể được thừa kế.', 'Trường đại học yêu cầu sinh viên gốc Tây Ban Nha phải đăng ký vào một chương trình tiếng Tây Ban Nha được thiết kế đặc biệt không có sẵn cho sinh viên không phải gốc Tây Ban Nha.'),
    ('1011edbe-b654-5c93-b70a-158d2c7cd050', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'humanity', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/hjuˈmænɪti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/humanity-us.mp3', 'Mankind; human beings as a group.', 'Philosophy is a humanity while psychology is a science.', 'Society & Culture', 'nhân loại', 'Loài người; con người như một nhóm.', 'Triết học là một môn nhân văn trong khi tâm lý học là một môn khoa học.'),
    ('44ef7587-2d2e-5ece-ad3a-b98b639133de', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'ideology', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌaɪ.diːˈɒl.ə.d͡ʒiː/', 'audio/ideology.mp3', 'Doctrine, philosophy, body of beliefs or principles belonging to an individual or group.', 'A dictatorship, in order to secure its reign, bans things that do not conform to its ideology.', 'Society & Culture', 'hệ tư tưởng', 'Học thuyết, triết lý, tập hợp niềm tin hoặc nguyên tắc thuộc về một cá nhân hoặc nhóm.', 'Một chế độ độc tài, để bảo đảm sự cai trị của mình, cấm những thứ không phù hợp với hệ tư tưởng của nó.'),
    ('aa295bfb-e793-52a2-a3cd-b4443b57da9c', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'inappropriate', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˌɪnəˈpɹəʊpɹi.ət/', 'audio/inappropriate.mp3', 'Not appropriate; not suitable for the situation, time, or place.', 'It is inappropriate to burp at a formal dinner.', 'Society & Culture', 'không phù hợp', 'Không thích hợp; không phù hợp với tình huống, thời gian, hoặc địa điểm.', 'Ợ hơi trong một bữa tối trang trọng là không phù hợp.'),
    ('1ebb34ba-50ab-556d-bd68-97b0d66c2f2f', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'inclusion', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɪnˈkluːʒən/', 'audio/inclusion.mp3', 'An addition or annex to a group, set, or total.', 'The poem was a new inclusion in the textbook.', 'Society & Culture', 'sự bao gồm', 'Một sự bổ sung hoặc phụ lục vào một nhóm, tập hợp, hoặc tổng thể.', 'Bài thơ là một sự bổ sung mới vào sách giáo khoa.'),
    ('28b70227-19a0-577b-b00a-6ec6663d0e07', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'influential', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ɪnfluˈɛnʃəl/', 'audio/influential.mp3', 'A person who has influence', 'Jane was very influential in getting the motion passed.', 'Society & Culture', 'có ảnh hưởng', 'Một người có ảnh hưởng', 'Jane đã có ảnh hưởng rất lớn trong việc thông qua đề xuất.'),
    ('3f053c86-8b6c-5584-9248-67ca6fea9f82', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'interfere', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˌɪntəˈfɪə/', 'audio/interfere.mp3', 'To get involved or involve oneself, causing disturbance.', 'I always try not to interfere with other people’s personal affairs.', 'Society & Culture', 'can thiệp', 'Tham gia hoặc tự mình tham gia, gây ra xáo trộn.', 'Tôi luôn cố gắng không can thiệp vào công việc cá nhân của người khác.'),
    ('2ef2ca0b-4833-5c7c-85a6-2e95cfe23e99', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'interference', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌɪntəɹˈfiɹɨns/', 'audio/interference.mp3', 'The act of interfering with something, or something that interferes.', 'They were glued to the TV, as the referee called out a fifteen yard penalty for interference.', 'Society & Culture', 'sự can thiệp', 'Hành động can thiệp vào một cái gì đó, hoặc một cái gì đó gây cản trở.', 'Họ dán mắt vào TV, khi trọng tài thổi phạt mười lăm thước vì lỗi cản trở.'),
    ('e8cb6684-fe67-5e2a-ac0f-fc270e961c37', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'invoke', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ɪnˈvoʊk/', 'audio/invoke.mp3', 'To call upon (a person, a god) for help, assistance or guidance.', 'The envoy invoked the King of Kings''s magnanimity to reduce his province''s tribute after another drought.', 'Society & Culture', 'cầu khẩn', 'Kêu gọi (một người, một vị thần) để được giúp đỡ, hỗ trợ hoặc hướng dẫn.', 'Sứ giả đã cầu khẩn lòng khoan dung của Vua của các Vị Vua để giảm cống nạp cho tỉnh của ông sau một đợt hạn hán khác.'),
    ('8be520f5-3db3-57ad-b87f-4027a5df6aec', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'kingdom', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkɪŋdəm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/kingdom-us.mp3', 'A realm having a king and/or queen as its actual or nominal sovereign.', 'the kingdom of the dead', 'Society & Culture', 'vương quốc', 'Một vương quốc có vua và/hoặc nữ hoàng là người đứng đầu thực tế hoặc danh nghĩa.', 'vương quốc của người chết'),
    ('855da8cc-b3b0-5b60-9a4b-5e004aac2024', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'legacy', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈleɪɡəsi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/legacy-us.mp3', 'Money or property bequeathed to someone in a will.', 'John Muir left as his legacy an enduring spirit of respect for the environment.', 'Society & Culture', 'di sản', 'Tiền hoặc tài sản được để lại cho ai đó trong di chúc.', 'John Muir để lại một tinh thần tôn trọng môi trường bền vững như di sản của ông.'),
    ('32cb2351-0f57-5f6c-831e-a2679d4ff9ff', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'lesbian', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈlɛzbi.ən/', 'audio/lesbian.mp3', 'A homosexual woman, one who is mostly or exclusively sexually or romantically attracted to other women.', 'She is lesbian.', 'Society & Culture', 'đồng tính nữ', 'Một phụ nữ đồng tính, người bị thu hút về mặt tình dục hoặc lãng mạn chủ yếu hoặc hoàn toàn với phụ nữ khác.', 'Cô ấy là người đồng tính nữ.'),
    ('ff673c8c-95d8-50c2-8f7e-3f3b9eea9b1b', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'liberal', 'C1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "C1"}, {"pos": "n", "level": "C1"}]'::jsonb, '/ˈlɪbɹəl/', 'audio/liberal.mp3', 'One with liberal views, supporting individual liberty (see Wikipedia''s article on Liberalism).', '1983, David Leslie Wagner, The Seven liberal arts in the Middle Ages', 'Society & Culture', 'tự do', 'Người có quan điểm tự do, ủng hộ quyền tự do cá nhân (xem bài viết của Wikipedia về Chủ nghĩa Tự do).', '1983, David Leslie Wagner, Bảy môn nghệ thuật tự do thời Trung cổ'),
    ('15948dd6-4ccc-56e3-8413-6fb8136e5295', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'liberty', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈlɪbɚti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/liberty-us.mp3', 'The condition of being free from control or restrictions.', 'The army is here, your liberty is assured.', 'Society & Culture', 'tự do', 'Tình trạng không bị kiểm soát hoặc hạn chế.', 'Quân đội đã ở đây, tự do của bạn được đảm bảo.'),
    ('8a413c0b-238d-59ee-8161-3f0d67906dbb', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'march', 'C1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "C1"}, {"pos": "v", "level": "C1"}]'::jsonb, '/mɑːtʃ/', 'audio/march.mp3', 'A formal, rhythmic way of walking, used especially by soldiers, bands and in ceremonies.', 'the march of time', 'Society & Culture', 'cuộc diễu hành', 'Một cách đi bộ trang trọng, nhịp nhàng, đặc biệt được sử dụng bởi binh lính, các ban nhạc và trong các nghi lễ.', 'bước tiến của thời gian'),
    ('e8313e6e-8454-596a-befc-d0a46208ca94', '4ef5190b-241b-5d14-bb49-9ce5295d6981', 'marginal', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈmɑːˌdʒɪn.əl/', 'audio/marginal.mp3', 'Something that is marginal.', 'In recent years there has been an increase in violence against marginal groups.', 'Society & Culture', 'ngoài lề, thiểu số', 'Một cái gì đó là ngoài lề.', 'Trong những năm gần đây, bạo lực chống lại các nhóm thiểu số đã gia tăng.')
ON CONFLICT (desk_id, word) DO NOTHING;

