INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('66943cb4-4271-5ca7-bb57-66d6b4665baf', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'acceptance', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ək.ˈsɛp.təns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/acceptance-us.mp3', 'The act of accepting; a receiving of something offered, with acquiescence, approbation, or satisfaction; especially, favourable reception; approval.', 'the acceptance of a gift, office, doctrine, etc.', 'Emotions & Feelings', 'sự chấp nhận', 'Hành động chấp nhận; sự tiếp nhận một thứ được đề nghị, với sự bằng lòng, tán thành, hoặc hài lòng; đặc biệt, sự tiếp nhận thuận lợi; sự chấp thuận.', 'sự chấp nhận một món quà, chức vụ, học thuyết, v.v.'),
    ('1918ded5-f39c-5b25-bb1e-d6f886dc5bcc', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'affection', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/əˈfɛkʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/affection-us.mp3', 'The act of affecting or acting upon.', 'I have a lot of affection for my little sister.', 'Emotions & Feelings', 'tình cảm', 'Hành động ảnh hưởng hoặc tác động lên.', 'Tôi có rất nhiều tình cảm với em gái nhỏ của mình.'),
    ('91846652-0ca0-58fe-b62e-ec4140eb9296', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'appealing', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/əˈpiː.lɪŋ/', 'audio/appealing.mp3', 'To call upon another to decide a question controverted, to corroborate a statement, to vindicate one''s rights, etc.', 'I appeal to all of you to help the orphans.', 'Emotions & Feelings', 'hấp dẫn, thu hút', 'Kêu gọi người khác quyết định một câu hỏi đang tranh cãi, xác nhận một tuyên bố, bảo vệ quyền lợi của một người, v.v.', 'Tôi kêu gọi tất cả các bạn hãy giúp đỡ những trẻ mồ côi.'),
    ('9fd1b378-2087-5ec6-96a4-0b080814ef10', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'appreciation', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/əˌpɹiː.ʃiˈeɪ.ʃən/', 'audio/appreciation.mp3', 'A fair valuation or estimate of merit, worth, weight, etc.; recognition of excellence.', 'We give to you this trophy as a token of our appreciation of all your years of service.', 'Emotions & Feelings', 'sự đánh giá cao, cảm kích', 'Một sự đánh giá hoặc ước tính công bằng về giá trị, công lao, trọng lượng, v.v.; sự công nhận sự xuất sắc.', 'Chúng tôi trao cho bạn chiếc cúp này như một biểu tượng cho sự cảm kích của chúng tôi đối với tất cả những năm phục vụ của bạn.'),
    ('aeb5aab3-dc36-53c3-81ad-d8b486a395dd', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'aspiration', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌæspəˈɹeɪʃən/', 'audio/aspiration.mp3', 'The act of aspiring or ardently desiring; an ardent wish or desire, chiefly after what is elevated or spiritual (with common adjunct adpositions being to and of).', 'Morgan has an aspiration of winning the game.', 'Emotions & Feelings', 'khát vọng', 'Hành động khao khát hoặc mong muốn tha thiết; một mong ước hoặc khát vọng tha thiết, chủ yếu hướng đến những gì cao quý hoặc tinh thần (với các giới từ phụ trợ phổ biến là ''to'' và ''of'').', 'Morgan có khát vọng chiến thắng trò chơi.'),
    ('4488f4fa-834a-535c-bae2-0b2b8bb9f6e9', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'aspire', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/əˈspaɪə(ɹ)/', 'audio/aspire.mp3', 'To have a strong desire or ambition to achieve something.', 'He aspires to become a successful doctor.', 'Emotions & Feelings', 'khao khát', 'Có một mong muốn hoặc tham vọng mạnh mẽ để đạt được điều gì đó.', 'Anh ấy khao khát trở thành một bác sĩ thành công.'),
    ('a5769269-97ac-5414-a835-cd9bd0b84f7b', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'betray', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/bəˈtɹeɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/betray-us.mp3', 'To deliver into the hands of an enemy by treachery or fraud, in violation of trust; to give up treacherously or faithlessly.', 'an officer betrayed the city', 'Emotions & Feelings', 'phản bội', 'Trao vào tay kẻ thù bằng sự phản bội hoặc gian lận, vi phạm lòng tin; từ bỏ một cách phản bội hoặc bội tín.', 'một sĩ quan đã phản bội thành phố'),
    ('61f59603-5a04-5f95-abf5-2a722668dc72', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'boast', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/bəʊst/', 'audio/boast.mp3', 'A brag; ostentatious positive appraisal of oneself.', 'It was his regular boast that he could eat two full English breakfasts in one sitting.', 'Emotions & Feelings', 'khoe khoang', 'Sự khoe khoang; đánh giá tích cực phô trương về bản thân.', 'Anh ấy thường khoe rằng mình có thể ăn hai bữa sáng kiểu Anh đầy đủ trong một lần ngồi.'),
    ('08802b62-55bc-5d56-a1d6-1ed46fcf6378', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'burden', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈbɜːdn/', 'audio/burden.mp3', 'A heavy load.', 'a ship of a hundred tons burden', 'Emotions & Feelings', 'gánh nặng', 'Một gánh nặng.', 'một con tàu có trọng tải một trăm tấn'),
    ('3de99c23-6996-5a42-b8f7-2db2b237151e', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'caution', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkɔːʃ(ə)n/', 'audio/caution.mp3', 'Precept or warning against evil or danger of any kind; exhortation to wariness; advice; injunction; prudence in regard to danger; provident care', 'The guideline expressed caution against excessive radiographic imaging.', 'Emotions & Feelings', 'sự thận trọng', 'Lời răn hoặc cảnh báo chống lại cái ác hoặc nguy hiểm bất kỳ; lời khuyên nên thận trọng; lời khuyên; mệnh lệnh; sự thận trọng liên quan đến nguy hiểm; sự quan tâm dự phòng', 'Hướng dẫn thể hiện sự thận trọng chống lại việc chụp X-quang quá mức.'),
    ('da3bab80-2414-552a-8760-40d97ff91640', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'cautious', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈkɔːʃəs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cautious-us.mp3', 'Careful; using or exercising caution; tentative', 'He took a few cautious steps toward the cave.', 'Emotions & Feelings', 'thận trọng', 'Cẩn thận; sử dụng hoặc thực hành sự thận trọng; dè dặt', 'Anh ấy bước vài bước thận trọng về phía hang động.'),
    ('6ff2b46a-5f56-58ae-860c-4235e49cbce4', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'chaos', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkeɪ.ɒs/', 'audio/chaos.mp3', 'The unordered state of matter in classical accounts of cosmogony.', 'After the earthquake, the local hospital was in chaos', 'Emotions & Feelings', 'hỗn loạn', 'Trạng thái vô trật tự của vật chất trong các tường thuật cổ điển về sự hình thành vũ trụ.', 'Sau trận động đất, bệnh viện địa phương rơi vào tình trạng hỗn loạn'),
    ('e90ee0aa-c8f5-59ff-860e-8e3770bcbf44', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'closure', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkləʊ.ʒə(ɹ)/', 'audio/closure.mp3', 'An event or occurrence that signifies an ending.', 'the closure of a door, or of a chink', 'Emotions & Feelings', 'sự kết thúc', 'Một sự kiện hoặc sự việc đánh dấu sự kết thúc.', 'sự đóng cửa, hoặc sự khép kín một khe hở'),
    ('fb0fcd6d-6a4b-584a-92a3-a0e39b47852f', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'confront', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/kɒnˈfɹɒnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/confront-us.mp3', 'To stand or meet facing, especially in competition, hostility or defiance; to come face to face with', 'We should confront him about the missing money.', 'Emotions & Feelings', 'đối mặt', 'Đứng hoặc gặp mặt đối mặt, đặc biệt trong cạnh tranh, thù địch hoặc thách thức; đối diện trực tiếp.', 'Chúng ta nên đối mặt với anh ta về số tiền bị mất.'),
    ('b2c6347f-dcfe-5a19-abac-585af867ca4d', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'conscience', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/kɒnʃəns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/conscience-us.mp3', 'The moral sense of right and wrong, chiefly as it affects one''s own behaviour.', 'Your conscience is your highest authority.', 'Emotions & Feelings', 'lương tâm', 'Ý thức đạo đức về đúng và sai, chủ yếu ảnh hưởng đến hành vi của chính mình.', 'Lương tâm của bạn là thẩm quyền cao nhất của bạn.'),
    ('c94b8f49-113f-5ca3-b523-58e48b48385d', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'contemplate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈkɒn.təmˌpleɪt/', 'audio/contemplate.mp3', 'To look at on all sides or in all its aspects; to view or consider with continued attention; to regard with deliberate care; to meditate on; to study, ponder, or consider.', 'I contemplated doing the project myself, but it would have taken too long.', 'Emotions & Feelings', 'suy ngẫm', 'Nhìn vào tất cả các mặt hoặc trong mọi khía cạnh của nó; xem xét hoặc cân nhắc với sự chú ý liên tục; quan tâm với sự cẩn thận có chủ ý; suy ngẫm về; nghiên cứu, cân nhắc hoặc xem xét.', 'Tôi đã suy ngẫm về việc tự mình làm dự án, nhưng nó sẽ mất quá nhiều thời gian.'),
    ('78803bd9-d1a3-58d8-bd59-9a302fced1ca', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'crush', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/kɹʌʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/crush-au.mp3', 'A violent collision or compression; a crash; destruction; ruin.', 'a crush at a reception', 'Emotions & Feelings', 'nghiền nát / sự say mê', 'Một vụ va chạm hoặc nén mạnh; một vụ đâm; sự phá hủy; sự hủy hoại.', 'sự chen lấn tại một buổi tiếp tân'),
    ('3a747d47-3d88-5051-9cf7-e3d9224eb6c3', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'curiosity', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌkjʊəɹɪˈɒsɪti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/curiosity-us.mp3', '(uncountable) Inquisitiveness; the tendency to ask and learn about things by asking questions, investigating, or exploring.', 'He put the strangely shaped rock in his curiosity cabinet.', 'Emotions & Feelings', 'sự tò mò', '(Không đếm được) Tính tò mò; xu hướng hỏi và tìm hiểu về mọi thứ bằng cách đặt câu hỏi, điều tra hoặc khám phá.', 'Anh ấy đặt viên đá hình thù kỳ lạ vào tủ trưng bày hiện vật lạ của mình.'),
    ('34859619-d44c-519b-bfc2-3ca5a1e78bc6', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'dedicated', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈdɛdɪkeɪtəd/', 'audio/dedicated.mp3', 'To set apart for a deity or for religious purposes; consecrate.', 'dedicated their money to scientific research.', 'Emotions & Feelings', 'tận tâm, cống hiến', 'Dành riêng cho một vị thần hoặc cho mục đích tôn giáo; thánh hóa.', 'dành tiền của họ cho nghiên cứu khoa học.'),
    ('0e918b65-dcd9-553c-bcbb-a6cc6fc348d4', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'defy', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/dɪˈfaɪ/', 'audio/defy.mp3', 'A challenge.', 'to defy an enemy; to defy the power of a magistrate; to defy the arguments of an opponent; to defy public opinion', 'Emotions & Feelings', 'thách thức, bất chấp', 'Một thách thức.', 'thách thức kẻ thù; thách thức quyền lực của một quan tòa; thách thức lập luận của đối thủ; thách thức dư luận'),
    ('de23834a-c6d4-566a-8ade-2d64c96e63af', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'denial', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/dɪˈnaɪ.əl/', 'audio/denial.mp3', 'The negation in logic.', 'The denial of "There might be X" is the null, "False, there is no X."', 'Emotions & Feelings', 'sự phủ nhận', 'Sự phủ định trong logic.', 'Sự phủ định của "Có thể có X" là giá trị null, "Sai, không có X."'),
    ('805eb7ec-c72c-5e31-8005-7a697fb96061', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'distress', 'C1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "C1"}, {"pos": "v", "level": "C1"}]'::jsonb, '/dɪˈstɹɛs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/distress-us.mp3', '(Cause of) discomfort.', 'She distressed the new media cabinet so that it fit with the other furniture in the room.', 'Emotions & Feelings', 'đau khổ, làm đau khổ', '(Nguyên nhân của) sự khó chịu.', 'Cô ấy đã làm cho tủ truyền thông mới trông cũ đi để nó phù hợp với các đồ nội thất khác trong phòng.'),
    ('6b4a1504-3618-5fdd-9a6c-01cbcd1751a5', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'disturbing', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/dɪsˈtɜːbɪŋ/', 'audio/disturbing.mp3', 'To confuse a quiet, constant state or a calm, continuous flow, in particular: thoughts, actions or liquids.', 'A school of fish disturbed the water.', 'Emotions & Feelings', 'gây bất an, phiền nhiễu', 'Làm rối loạn một trạng thái yên tĩnh, ổn định hoặc một dòng chảy liên tục, êm đềm, cụ thể là: suy nghĩ, hành động hoặc chất lỏng.', 'Một đàn cá làm xáo động mặt nước.'),
    ('f4772f35-cdce-5fea-bbfd-2a5a4fbd7eac', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'eager', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈiːɡə/', 'audio/eager.mp3', 'Sharp; sour; acid.', 'I was eager to show my teacher how much I''d learned over the holidays.', 'Emotions & Feelings', 'háo hức', 'Sắc; chua; axit. (Nghĩa cổ, nghĩa hiện đại: nhiệt tình, mong đợi).', 'Tôi rất háo hức cho giáo viên thấy tôi đã học được bao nhiêu trong kỳ nghỉ.'),
    ('82dfe923-ed58-5523-b85d-ed7d1c9b620f', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'ease', 'C1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "C1"}, {"pos": "v", "level": "C1"}]'::jsonb, '/iːz/', 'audio/ease.mp3', 'Ability, the means to do something, particularly:', 'He eased his conscience by confessing.', 'Emotions & Feelings', 'sự thoải mái', 'Khả năng, phương tiện để làm điều gì đó, cụ thể là: sự dễ dàng, thoải mái.', 'Anh ấy làm nhẹ lòng bằng cách thú tội.'),
    ('8bff2105-3977-5628-a8b0-987a8c7fff1b', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'embarrassment', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɪmˈbæɹəsmənt/', 'audio/embarrassment.mp3', 'A state of discomfort arising from bashfulness or consciousness of having violated a social rule; humiliation.', 'Kevin, you are an embarrassment to this family.', 'Emotions & Feelings', 'sự xấu hổ', 'Trạng thái khó chịu phát sinh từ sự e thẹn hoặc ý thức về việc đã vi phạm một quy tắc xã hội; sự bối rối, xấu hổ.', 'Kevin, con là nỗi xấu hổ của gia đình này.'),
    ('59a5eb78-3ac0-5ef4-9d76-29be03000e09', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'encouraging', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ɪnˈkʌɹɪd͡ʒɪŋ/', 'audio/encouraging.mp3', 'To mentally support; to motivate, give courage, hope or spirit.', 'I encouraged him during his race.', 'Emotions & Feelings', 'khích lệ, động viên', 'Hỗ trợ về mặt tinh thần; tạo động lực, cho can đảm, hy vọng hoặc tinh thần.', 'Tôi đã động viên anh ấy trong cuộc đua.'),
    ('d364050f-6c69-52d4-8219-b136c066ab93', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'endure', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ɪnˈdjɔː(ɹ)/', 'audio/endure.mp3', 'To continue or carry on, despite obstacles or hardships; to persist.', 'The singer''s popularity endured for decades.', 'Emotions & Feelings', 'chịu đựng, kéo dài', 'Tiếp tục hoặc duy trì, bất chấp trở ngại hoặc khó khăn; kiên trì.', 'Sự nổi tiếng của ca sĩ kéo dài hàng thập kỷ.'),
    ('8f748146-8c53-5415-8a73-1fbc7b10190a', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'evoke', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ɪˈvəʊk/', 'audio/evoke.mp3', 'To call out; to draw out or bring forth.', 'Being here evokes long forgotten memories.', 'Emotions & Feelings', 'gợi lên', 'Gọi ra; rút ra hoặc mang ra.', 'Ở đây gợi lên những ký ức đã quên từ lâu.'),
    ('9fb020e9-918c-5436-96ee-64bb5593c6a1', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'exaggerate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ɛɡˈzæ.dʒə.ɹeɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/exaggerate-us.mp3', 'To overstate, to describe more than is fact.', 'He said he''d slept with hundreds of girls, but I know he''s exaggerating. The real number is about ten.', 'Emotions & Feelings', 'phóng đại', 'Nói quá, mô tả nhiều hơn sự thật.', 'Anh ấy nói đã ngủ với hàng trăm cô gái, nhưng tôi biết anh ấy đang phóng đại. Con số thực là khoảng mười.'),
    ('ab9d4e2e-c219-5932-8d82-f116f3710105', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'favourable', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈfeɪv(ə)ɹəbəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/favourable-us.mp3', 'Pleasing, encouraging or approving.', 'The candidate wearing the business suite made a favourable impression.', 'Emotions & Feelings', 'thuận lợi, tích cực', 'Làm hài lòng, khích lệ hoặc tán thành.', 'Ứng viên mặc bộ vest công sở đã tạo ấn tượng tích cực.'),
    ('1b89fec9-ade9-5e13-a842-86217945c05b', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'fierce', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/fɪəs/', 'audio/fierce.mp3', 'Exceedingly violent, severe, ferocious, cruel or savage.', 'A fierce storm battered the coast.', 'Emotions & Feelings', 'dữ dội, mãnh liệt', 'Cực kỳ bạo lực, nghiêm trọng, hung dữ, tàn bạo hoặc dã man.', 'Một cơn bão dữ dội tàn phá bờ biển.'),
    ('20c9632f-2072-54cc-a232-5230cb82cc0b', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'frustrated', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/fɹəsˈtɹeɪt.ɪd/', 'audio/frustrated.mp3', 'To disappoint or defeat; to vex by depriving of something expected or desired.', 'It frustrates me to do all this work and then lose it all.', 'Emotions & Feelings', 'bực bội', 'Làm thất vọng hoặc đánh bại; làm bực mình bằng cách tước đoạt điều gì đó mong đợi hoặc mong muốn.', 'Thật bực bội khi làm tất cả công việc này và rồi mất hết.'),
    ('9e019fe8-019e-5c22-8deb-ba29ff0c4cad', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'frustrating', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/fɹʌˈstɹeɪ̯tɪŋ/', 'audio/frustrating.mp3', 'To disappoint or defeat; to vex by depriving of something expected or desired.', 'It frustrates me to do all this work and then lose it all.', 'Emotions & Feelings', 'gây bực bội', 'Làm thất vọng hoặc đánh bại; làm bực mình bằng cách tước đoạt điều gì đó mong đợi hoặc mong muốn.', 'Thật bực bội khi làm tất cả công việc này và rồi mất hết.'),
    ('13c1f911-0789-5e21-bac8-89e69c0f7a01', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'gaze', 'C1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "C1"}, {"pos": "v", "level": "C1"}]'::jsonb, '/ɡeɪz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/gaze-us.mp3', 'A fixed look; a look of eagerness, wonder, or admiration; a continued look of attention.', 'In fact, for Antonioni this gazing is probably the most fundamental of all cognitive activities ... (from Thinking in the Absence of Image)', 'Emotions & Feelings', 'cái nhìn chăm chú', 'Một cái nhìn cố định; một cái nhìn đầy háo hức, ngạc nhiên, hoặc ngưỡng mộ; một cái nhìn chú ý liên tục.', 'Trên thực tế, đối với Antonioni, sự nhìn chăm chú này có lẽ là hoạt động nhận thức cơ bản nhất trong tất cả... (trích từ Suy nghĩ trong sự vắng mặt của Hình ảnh)'),
    ('91d61697-19f8-587c-83e4-6265f25302dc', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'glance', 'C1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "C1"}, {"pos": "v", "level": "C1"}]'::jsonb, '/ɡlɑːns/', 'audio/glance.mp3', 'A brief or cursory look.', 'copper glance', 'Emotions & Feelings', 'liếc nhìn', 'Một cái nhìn thoáng qua hoặc sơ sài.', 'quặng đồng glance'),
    ('7c4cac0f-ad7d-5fe4-a594-87358cd7091c', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'glimpse', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɡlɪmps/', 'https://api.dictionaryapi.dev/media/pronunciations/en/glimpse-us.mp3', 'A brief look, glance, or peek.', 'I only got a glimpse of the car, so I can tell you the colour but not the registration number.', 'Emotions & Feelings', 'cái nhìn thoáng qua', 'Một cái nhìn, liếc mắt, hoặc nhìn lén nhanh.', 'Tôi chỉ nhìn thoáng qua chiếc xe, vì vậy tôi có thể nói cho bạn biết màu sắc nhưng không phải số đăng ký.'),
    ('32ffbd43-e17b-576d-884b-95a3744df858', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'glorious', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈɡlɔː.ɹi.əs/', 'audio/glorious.mp3', 'Exhibiting attributes, qualities, or acts that are worthy of or receive glory.', 'glorious deeds', 'Emotions & Feelings', 'vinh quang, rực rỡ', 'Thể hiện những thuộc tính, phẩm chất, hoặc hành động xứng đáng hoặc nhận được vinh quang.', 'những hành động vinh quang'),
    ('28f9d3e9-fafe-594e-88e1-8e416f0fa43f', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'grief', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɡɹiːf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/grief-uk.mp3', 'Suffering, hardship.', 'She was worn out from so much grief.', 'Emotions & Feelings', 'nỗi đau buồn', 'Sự đau khổ, gian khó.', 'Cô ấy kiệt sức vì quá nhiều đau buồn.'),
    ('ea24c5d7-9cf4-5c97-9c1b-727e2750f2c2', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'harsh', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/hɑːʃ/', 'audio/harsh.mp3', 'To negatively criticize.', 'Quit harshing me already, I said that I was sorry!', 'Emotions & Feelings', 'khắc nghiệt', 'Chỉ trích một cách tiêu cực.', 'Đừng chỉ trích tôi nữa, tôi đã nói là tôi xin lỗi rồi mà!'),
    ('b33d43ad-a3b8-57a1-a881-2c36ee7f708e', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'hopeful', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈhəʊpfəl/', 'audio/hopeful.mp3', 'Someone who is hoping for success or victory, especially as a candidate in a political election.', 'Several presidential hopefuls are campaigning in New Hampshire this week.', 'Emotions & Feelings', 'đầy hy vọng', 'Người đang hy vọng thành công hoặc chiến thắng, đặc biệt là ứng cử viên trong một cuộc bầu cử chính trị.', 'Một vài ứng cử viên tổng thống đầy hy vọng đang vận động tranh cử ở New Hampshire tuần này.'),
    ('c977461a-1268-5b1b-8f61-b5bac4bfd4b2', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'hostile', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈhɒstaɪl/', 'audio/hostile.mp3', '(chiefly in the plural) An enemy.', 'a hostile country', 'Emotions & Feelings', 'thù địch', '(chủ yếu ở số nhiều) Kẻ thù.', 'một quốc gia thù địch'),
    ('4b9fd9e2-5f9a-5b2b-bf97-3b1278c3c863', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'hostility', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/hɒˈstɪlɪti/', 'audio/hostility.mp3', 'The state of being hostile.', 'My resentment and anger towards you caused hostility and a division between us.', 'Emotions & Feelings', 'sự thù địch', 'Tình trạng thù địch.', 'Sự oán giận và tức giận của tôi đối với bạn đã gây ra sự thù địch và chia rẽ giữa chúng ta.'),
    ('6f50d408-5f2c-5dd5-995b-4d0a0fd6d47c', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'indulge', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ɪnˈdʌldʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/indulge-us.mp3', '(often followed by "in"): To yield to a temptation or desire.', 'He looked at the chocolate but didn''t indulge.', 'Emotions & Feelings', 'nuông chiều', '(thường theo sau bởi "in"): Nhượng bộ trước một cám dỗ hoặc ham muốn.', 'Anh ấy nhìn vào thanh sô cô la nhưng đã không nuông chiều bản thân.'),
    ('0aed60b1-c4d5-5b26-9598-f1fbc3242476', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'insult', 'C1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "C1"}, {"pos": "v", "level": "C1"}]'::jsonb, '/ɪnˈsʌlt/', 'audio/insult.mp3', 'Action or form of speech deliberately intended to be rude; a particular act or statement having this effect.', 'The way the orchestra performed tonight was an insult to my ears.', 'Emotions & Feelings', 'sự xúc phạm', 'Hành động hoặc hình thức nói chuyện cố ý thô lỗ; một hành động hoặc tuyên bố cụ thể có tác dụng này.', 'Cách dàn nhạc biểu diễn tối nay là một sự xúc phạm đến tai tôi.'),
    ('7b70cfff-83de-5f26-878e-c10cc2dcc7ef', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'intent', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɪnˈtɛnt/', 'audio/intent.mp3', 'A purpose; something that is intended.', 'a mind intent on self-improvement', 'Emotions & Feelings', 'ý định', 'Một mục đích; điều gì đó được dự định.', 'một tâm trí tập trung vào việc tự cải thiện'),
    ('95029dac-18bd-5d1a-b138-a1a67919cb0e', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'meaningful', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈminɪŋfʊl/', 'audio/meaningful.mp3', 'Having meaning, significant.', 'I think we made a meaningful contribution to this project today.', 'Emotions & Feelings', 'có ý nghĩa', 'Có ý nghĩa, quan trọng.', 'Tôi nghĩ chúng ta đã có một đóng góp có ý nghĩa cho dự án này hôm nay.'),
    ('8821fc75-9e5a-558f-8a8e-f34eba08dcbb', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'mercy', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈmɜːsi/', 'audio/mercy.mp3', 'Relenting; forbearance to cause or allow harm to another.', 'She took mercy on him and quit embarrassing him.', 'Emotions & Feelings', 'lòng thương, khoan dung', 'Sự mềm lòng; sự kiềm chế không gây hoặc cho phép gây hại cho người khác.', 'Cô ấy thương hại anh ta và ngừng làm anh xấu hổ.'),
    ('1483f0b9-d4f1-5bd8-833d-def223fa0393', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'misery', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈmɪz(ə)ɹɪ/', 'audio/misery.mp3', 'Great unhappiness; extreme pain of body or mind; wretchedness; distress; woe.', 'Ever since his wife left him you can see the misery on his face.', 'Emotions & Feelings', 'sự khốn khổ', 'Nỗi bất hạnh lớn; nỗi đau thể xác hoặc tinh thần cùng cực; sự khốn cùng; sự đau khổ; tai ương.', 'Kể từ khi vợ bỏ đi, bạn có thể thấy sự khốn khổ trên khuôn mặt anh ấy.'),
    ('f2987ce5-9c64-5287-844c-932e766c38ff', '2093e83a-41c4-5960-ae33-e4342ef5ea26', 'motive', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈməʊtɪv/', 'audio/motive.mp3', 'An idea or communication that makes one want to act, especially from spiritual sources; a divine prompting.', 'No-one could understand why she had hidden the shovel; her motives were obscure at best.', 'Emotions & Feelings', 'động cơ', 'Một ý tưởng hoặc thông điệp khiến người ta muốn hành động, đặc biệt là từ nguồn gốc tinh thần; một sự thúc đẩy thiêng liêng.', 'Không ai có thể hiểu tại sao cô ấy lại giấu cái xẻng; động cơ của cô ấy tốt nhất là mơ hồ.')
