    ('2b96b8bc-fec7-5ef6-b7ec-3db27279ffe4', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'acute', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/əˈkjuːt/', 'audio/acute.mp3', 'A person who has the acute form of a disorder, such as schizophrenia.', 'The word ‘cafe’ often has an acute over the ‘e’.', 'Health & Body', 'cấp tính', 'Người mắc dạng cấp tính của một rối loạn, chẳng hạn như tâm thần phân liệt.', 'Từ ''cafe'' thường có dấu sắc trên chữ ''e''.'),
    ('f19e2a42-67fe-574d-8ac3-932c682c3ef1', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'administer', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ədˈmɪnɪstɚ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/administer-us.mp3', 'To cause to ingest (a drug), either by openly offering or through deceit.', 'We administered the medicine to our dog by mixing it in his food.', 'Health & Body', 'quản lý', 'Khiến cho uống (thuốc), bằng cách đưa công khai hoặc thông qua lừa dối.', 'Chúng tôi cho chó uống thuốc bằng cách trộn nó vào thức ăn của nó.'),
    ('fd27fe2a-4e12-5e1b-958f-1af720c28b40', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'appetite', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈæp.ə.taɪt/', 'audio/appetite.mp3', 'Desire to eat food or consume drink.', 'appetite for reading', 'Health & Body', 'sự thèm ăn, khẩu vị', 'Mong muốn ăn thức ăn hoặc tiêu thụ đồ uống.', 'khẩu vị đọc sách'),
    ('da6ffd0f-5944-5390-bfbf-73a3fe9898e3', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'bleed', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈbliːd/', 'audio/bleed.mp3', 'An incident of bleeding, as in haemophilia.', 'If her nose bleeds, try to use ice.', 'Health & Body', 'chảy máu', 'Một sự cố chảy máu, như trong bệnh máu khó đông.', 'Nếu mũi cô ấy chảy máu, hãy thử dùng đá.'),
    ('f25f927d-a71c-54b5-bc63-49fc8fa649f5', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'chronic', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈkɹɒnɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chronic-au.mp3', 'Marijuana, typically of high quality.', 'chronic unemployment; chronic poverty; chronic anger; chronic life', 'Health & Body', 'mãn tính', 'Cần sa, thường là loại chất lượng cao.', 'thất nghiệp mãn tính; nghèo đói mãn tính; sự tức giận mãn tính; cuộc sống mãn tính'),
    ('1c1d3b55-947d-592e-a94d-1c421cfc2ea8', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'clinical', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈklɪnɪkəl/', 'audio/clinical.mp3', 'A medical student''s session spent in a real-world nursing environment.', 'Medicine is now more often practiced in a clinical setting than in the home.', 'Health & Body', 'lâm sàng', 'Buổi thực hành của sinh viên y khoa trong môi trường điều dưỡng thực tế.', 'Y học ngày nay thường được thực hành trong môi trường lâm sàng hơn là tại nhà.'),
    ('48c80b18-ec21-57e6-a55c-6ca38360b486', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'conceive', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/kənˈsiːv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/conceive-us.mp3', 'To develop an idea; to form in the mind; to plan; to devise; to originate.', 'Assisted procreation can help those trying to conceive.', 'Health & Body', 'thụ thai, hình thành', 'Phát triển một ý tưởng; hình thành trong tâm trí; lên kế hoạch; nghĩ ra; khởi xướng.', 'Hỗ trợ sinh sản có thể giúp những người đang cố gắng thụ thai.'),
    ('37055eb8-7670-5b88-becf-1c50438b2392', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'coordination', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/koʊˌɔɹdɪˈneɪʃən/', 'audio/coordination.mp3', 'The act of coordinating, making different people or things work together for a goal or effect.', 'I''m terrible at sports; I have no coordination.', 'Health & Body', 'sự phối hợp', 'Hành động phối hợp, làm cho những người hoặc vật khác nhau làm việc cùng nhau vì một mục tiêu hoặc hiệu quả.', 'Tôi rất tệ trong thể thao; tôi không có sự phối hợp.'),
    ('105cf385-500b-58e8-9233-c3840d8cd5b3', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'crawl', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/kɹɔl/', 'audio/crawl.mp3', 'The act of moving slowly on hands and knees etc, or with frequent stops.', 'My computer has slowed down to a crawl since I installed that software package.', 'Health & Body', 'bò', 'Hành động di chuyển chậm trên tay và đầu gối, v.v., hoặc với nhiều điểm dừng.', 'Máy tính của tôi đã chậm đến mức ì ạch kể từ khi tôi cài đặt gói phần mềm đó.'),
    ('76d2f9ee-3d4f-52f8-ac42-d4c6b40118ba', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'damaging', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈdæmɪdʒɪŋ/', 'audio/damaging.mp3', 'To impair the soundness, goodness, or value of; to harm or cause destruction.', 'Be careful not to damage any of the fragile items while unpacking them.', 'Health & Body', 'gây hại', 'Làm suy giảm sự lành mạnh, tốt đẹp, hoặc giá trị; gây hại hoặc gây ra sự phá hủy.', 'Hãy cẩn thận không làm hư hỏng bất kỳ món đồ dễ vỡ nào khi mở chúng ra.'),
    ('f2a16ded-6325-59c1-837a-ea5026f77995', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'dependence', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/dɪˈpɛndəns/', 'audio/dependence.mp3', 'The state of being dependent, of relying upon another.', 'He had a deep dependence on her for guidance.', 'Health & Body', 'sự phụ thuộc', 'Trạng thái phụ thuộc, dựa vào người khác.', 'Anh ấy phụ thuộc sâu sắc vào cô ấy để được hướng dẫn.'),
    ('2077c845-08ac-51ce-96ae-53c41373cd3f', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'deteriorate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/dɪˈtɪəɹɪəɹeɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/deteriorate-uk.mp3', 'To make worse; to make inferior in quality or value; to impair.', 'to deteriorate the mind', 'Health & Body', 'xấu đi, suy giảm', 'Làm cho tệ hơn; làm cho chất lượng hoặc giá trị kém đi; làm suy yếu.', 'làm suy giảm trí óc'),
    ('6c00d195-8efa-5e6f-9970-69a734ea40cf', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'diagnosis', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/daɪəɡˈnəʊsɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/diagnosis-uk.mp3', 'To determine which disease is causing a sick person''s signs and symptoms; to find the diagnosis.', 'He was given the wrong treatment due to an erroneous diagnosis.', 'Health & Body', 'sự chẩn đoán', 'Xác định bệnh nào đang gây ra các dấu hiệu và triệu chứng của người bệnh; tìm ra chẩn đoán.', 'Ông ấy đã được điều trị sai do một chẩn đoán sai lầm.'),
    ('bc5b21d6-e2b4-5fcf-9e74-483917af3844', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'drown', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/dɹaʊn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/drown-us.mp3', 'To die from suffocation while immersed in water or other fluid.', 'The answers intelligence services seek are often drowned in the flood of information they can now gather.', 'Health & Body', 'chết đuối', 'Chết vì ngạt thở khi chìm trong nước hoặc chất lỏng khác.', 'Những câu trả lời mà các cơ quan tình báo tìm kiếm thường bị chìm trong biển thông tin mà giờ đây họ có thể thu thập.'),
    ('64203ef7-cb1f-52d2-834a-7649218aa89b', 'd6e176bf-99e8-5c69-99e8-0604b71482ba', 'dumb', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/dʌm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dumb-ca.mp3', 'Unable to speak; lacking power of speech (kept in "deaf, dumb, and blind").', 'His younger brother was born dumb, and communicated with sign language.', 'Health & Body', 'câm', 'Không thể nói; thiếu khả năng phát ngôn (thường dùng trong cụm ''điếc, câm, và mù'').', 'Em trai của anh ấy sinh ra đã bị câm, và giao tiếp bằng ngôn ngữ ký hiệu.'),
