    ('a48b183a-72c3-5f3f-bca4-aa03d827ce7d', 'eba2bc0a-a381-5202-9492-2e595e9a6435', 'specimen', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈspɛsɪmɪn/', 'audio/specimen.mp3', 'An individual instance that represents a class; an example.', 'early specimens of the art of Picasso', 'Science & Research', 'mẫu vật', 'Một cá thể đại diện cho một lớp; một ví dụ.', 'các mẫu vật đầu tiên của nghệ thuật Picasso'),
