    ('b5ed7dbf-a031-56c9-ab75-7394aee151cb', 'eba2bc0a-a381-5202-9492-2e595e9a6435', 'stabilize', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, NULL, 'audio/stabilize.mp3', 'To make stable.', 'Jody stabilized the table by putting a book under the short leg.', 'Science & Research', 'ổn định', 'Làm cho ổn định.', 'Jody ổn định cái bàn bằng cách đặt một cuốn sách dưới chân ngắn.'),
    ('550db8b3-c01e-547b-ae72-0a029574bc09', 'eba2bc0a-a381-5202-9492-2e595e9a6435', 'underlying', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, NULL, 'audio/underlying.mp3', 'To lie in a position directly beneath.', 'A stratum of clay underlies the surface gravel.', 'Science & Research', 'tiềm ẩn, cơ bản', 'Nằm ở vị trí ngay bên dưới.', 'Một lớp đất sét nằm bên dưới lớp sỏi bề mặt.'),
    ('93d0ce2f-662b-5af9-9b8d-df402b9bcce8', 'eba2bc0a-a381-5202-9492-2e595e9a6435', 'adaptation', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌædæpˈteɪʃən/', 'audio/adaptation.mp3', 'The process of adapting something or becoming adapted to a situation; adjustment, modification.', NULL, 'Science & Research', 'sự thích nghi', 'Quá trình thích ứng cái gì đó hoặc trở nên thích nghi với một tình huống; điều chỉnh, sửa đổi.', NULL),
    ('e2c63230-44b8-5d40-a406-c395dd7e6ac3', 'eba2bc0a-a381-5202-9492-2e595e9a6435', 'aluminium', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/əˈluːmɪnəm/', 'audio/aluminium.mp3', 'A light, silvery metal extracted from bauxite, and a chemical element (symbol Al) with an atomic number of 13.', NULL, 'Science & Research', 'nhôm', 'Một kim loại nhẹ, màu trắng bạc được chiết xuất từ bauxite, và là một nguyên tố hóa học (ký hiệu Al) với số nguyên tử 13.', NULL),
    ('35936509-8825-5ccb-8502-17a727ae3d49', 'eba2bc0a-a381-5202-9492-2e595e9a6435', 'apparatus', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/æpəˈɹɑːtəs/', 'audio/apparatus.mp3', 'The entirety of means whereby a specific production is made existent or task accomplished.', NULL, 'Science & Research', 'bộ máy, thiết bị', 'Toàn bộ các phương tiện mà nhờ đó một sản phẩm cụ thể được tạo ra hoặc một nhiệm vụ được hoàn thành.', NULL),
    ('eec03f10-60ca-53b0-a15a-31ac07f876cf', 'eba2bc0a-a381-5202-9492-2e595e9a6435', 'classification', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌklæsɪfɪˈkeɪʃən/', 'audio/classification.mp3', 'The act of forming into a class or classes; a distribution into groups, as classes, orders, families, etc., according to some common relations or attributes.', NULL, 'Science & Research', 'sự phân loại', 'Hành động hình thành thành một lớp hoặc các lớp; một sự phân phối vào các nhóm, như lớp, bộ, họ, v.v., theo một số mối quan hệ hoặc thuộc tính chung.', NULL),
