    ('1dc93074-5b98-50f0-b6ce-3c97670d53a8', 'f8062a5d-91fa-5ac0-a232-86c9eab817f1', 'transparent', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/tɹæn(t)sˈpæɹənt/', 'audio/transparent.mp3', '(of a material or object) See-through, clear; having the property that light passes through it almost undisturbed, such that one can see through it clearly.', 'The waters of the lake were transparent until the factory dumped waste there.', 'Appearance & Description', 'trong suốt', '(của một vật liệu hoặc vật thể) Có thể nhìn xuyên qua, rõ ràng; có đặc tính là ánh sáng đi qua nó hầu như không bị xáo trộn, đến mức người ta có thể nhìn xuyên qua nó một cách rõ ràng.', 'Nước của hồ vốn trong suốt cho đến khi nhà máy xả chất thải ở đó.'),
    ('250e871f-9217-5a93-8fd3-9faf300f7960', 'f8062a5d-91fa-5ac0-a232-86c9eab817f1', 'vague', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/veɪɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/vague-uk.mp3', 'A wandering; a vagary.', 'a vague term of abuse', 'Appearance & Description', 'mơ hồ, không rõ ràng', 'Sự lang thang; một ý nghĩ kỳ quặc.', 'một thuật ngữ mơ hồ để chửi bới'),
    ('802eafc6-2a1b-5e8d-8e7e-b80766ece6bc', 'f8062a5d-91fa-5ac0-a232-86c9eab817f1', 'vanish', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈvænɪʃ/', 'audio/vanish.mp3', 'The brief terminal part of a vowel or vocal element, differing more or less in quality from the main part.', 'a as in ale ordinarily ends with a vanish of i as in ill.', 'Appearance & Description', 'biến mất', 'Phần cuối ngắn gọn của một nguyên âm hoặc thành phần phát âm, khác biệt ít nhiều về chất lượng so với phần chính.', 'a trong từ ale thông thường kết thúc với âm biến mất của i như trong từ ill.'),
    ('cd0ef59f-385c-5c9c-b1a5-6afa835fd65a', 'f8062a5d-91fa-5ac0-a232-86c9eab817f1', 'varied', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈvɛəɹid/', 'audio/varied.mp3', 'Diverse or miscellaneous', 'He varies his magic tricks so as to minimize the possibility that any given audience member will see the same trick twice.', 'Appearance & Description', 'đa dạng', 'Đa dạng hoặc hỗn tạp', 'Anh ấy thay đổi các trò ảo thuật của mình để giảm thiểu khả năng bất kỳ khán giả nào xem cùng một trò hai lần.'),
    ('7c4f00c8-0b33-5ecb-8b80-3fd57e8f3279', 'f8062a5d-91fa-5ac0-a232-86c9eab817f1', 'widen', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈwaɪdən/', 'audio/widen.mp3', 'To become wide or wider.', 'His eyes widened as her negligee fell to the floor.', 'Appearance & Description', 'mở rộng', 'Trở nên rộng hoặc rộng hơn.', 'Mắt anh ấy mở to khi chiếc áo choàng ngủ của cô ấy rơi xuống sàn.')
