    ('315a2c7c-9d3c-5a61-8837-0623c76f71f0', '4513696e-efd4-589e-887c-a3ebf12533d0', 'adjustment', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/əˈdʒʌst.mənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/adjustment-us.mp3', 'The action of adjusting something', 'The credit card company made an adjustment to my account to waive the late fee.', 'Work & Career', 'sự điều chỉnh', 'Hành động điều chỉnh cái gì đó', 'Công ty thẻ tín dụng đã điều chỉnh tài khoản của tôi để miễn phí trễ hạn.'),
    ('32552089-4f79-5022-838d-590cbc8958f5', '4513696e-efd4-589e-887c-a3ebf12533d0', 'assemble', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/əˈsɛmbl̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/assemble-us.mp3', 'To put together.', 'He assembled the model ship.', 'Work & Career', 'lắp ráp', 'Để ghép lại với nhau.', 'Anh ấy lắp ráp mô hình con tàu.'),
