    ('cabf4a70-863b-5b1d-b972-c82bb87d17ce', '4513696e-efd4-589e-887c-a3ebf12533d0', 'breakdown', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈbɹeɪkdaʊn/', 'audio/breakdown.mp3', 'A failure, particularly mechanical; something that has failed', 'We saw a breakdown by the side of the road.', 'Work & Career', 'sự hỏng hóc', 'Một sự cố, đặc biệt là cơ khí; một thứ gì đó đã bị hỏng', 'Chúng tôi thấy một chiếc xe bị hỏng bên đường.'),
    ('116229a2-29de-5980-90ea-ec03dbc5fced', '4513696e-efd4-589e-887c-a3ebf12533d0', 'collaborate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/kəˈlabəɹeɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/collaborate-us.mp3', 'To work together with others to achieve a common goal.', 'Let''s collaborate on this project, and get it finished faster.', 'Work & Career', 'cộng tác', 'Làm việc cùng nhau với người khác để đạt được mục tiêu chung.', 'Hãy cùng cộng tác trong dự án này, và hoàn thành nó nhanh hơn.'),
    ('3663b48b-cb30-51c3-93a7-b47bc15a500f', '4513696e-efd4-589e-887c-a3ebf12533d0', 'collaboration', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/kəˌlæbəˈɹeɪʃən/', 'audio/collaboration.mp3', 'The act of collaborating.', 'Collaboration can be a useful part of the creative process.', 'Work & Career', 'sự cộng tác', 'Hành động cộng tác.', 'Sự cộng tác có thể là một phần hữu ích của quá trình sáng tạo.'),
    ('742d5616-f5ba-50f6-8b8a-e3fecd1797cd', '4513696e-efd4-589e-887c-a3ebf12533d0', 'competence', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkɒmpətəns/', 'audio/competence.mp3', 'The quality or state of being competent, i.e. able or suitable for a general role.', 'That question is out with the competence of this court and must be taken to a higher court.', 'Work & Career', 'năng lực', 'Phẩm chất hoặc trạng thái có năng lực, tức là có khả năng hoặc phù hợp cho một vai trò chung.', 'Câu hỏi đó nằm ngoài thẩm quyền của tòa án này và phải được chuyển lên tòa án cấp cao hơn.'),
    ('35d890d5-b98c-558f-ad47-936e55a1d4ed', '4513696e-efd4-589e-887c-a3ebf12533d0', 'competent', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈkɒmpətənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/competent-us.mp3', 'Having sufficient skill, knowledge, ability, or qualifications.', 'He is a competent skier and an expert snowboarder.', 'Work & Career', 'có năng lực', 'Có đủ kỹ năng, kiến thức, khả năng hoặc trình độ.', 'Anh ấy là một tay trượt tuyết có năng lực và một vận động viên trượt ván chuyên nghiệp.'),
    ('a1734018-18b6-5da6-aca1-d1e151ff5d6c', '4513696e-efd4-589e-887c-a3ebf12533d0', 'decisive', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/dɪˈsaɪsɪv/', 'audio/decisive.mp3', 'Having the power or quality of deciding a question or controversy; putting an end to contest or controversy; final; conclusive.', 'A decisive battle is fatal for one side''s war chances', 'Work & Career', 'quyết đoán', 'Có sức mạnh hoặc phẩm chất quyết định một câu hỏi hoặc tranh cãi; chấm dứt tranh chấp hoặc tranh cãi; cuối cùng; kết luận.', 'Một trận chiến quyết định là chí mạng đối với cơ hội chiến tranh của một bên'),
    ('956a3f91-c9fe-5a65-85c1-71552e7d5609', '4513696e-efd4-589e-887c-a3ebf12533d0', 'deploy', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/dɪˈplɔɪ/', 'audio/deploy.mp3', 'Deployment', '"Deploy two units of infantry along the enemy''s flank," the general ordered.', 'Work & Career', 'triển khai', 'Sự triển khai', '"Triển khai hai đơn vị bộ binh dọc theo sườn của kẻ thù," vị tướng ra lệnh.'),
    ('19446b21-98ea-5441-a536-695d5b5ad777', '4513696e-efd4-589e-887c-a3ebf12533d0', 'deputy', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈdɛpjəti/', 'audio/deputy.mp3', 'One appointed as the substitute of another, and empowered to act for them, in their name or their behalf; a substitute in office', 'As the deputy store manager, he is able to fire staff.', 'Work & Career', 'phó', 'Người được bổ nhiệm làm người thay thế cho người khác, được trao quyền hành động thay cho họ, nhân danh họ hoặc thay mặt họ; một người thay thế trong chức vụ.', 'Là phó quản lý cửa hàng, anh ấy có quyền sa thải nhân viên.'),
    ('a6991f46-9408-567c-aaa1-bfc05d368df9', '4513696e-efd4-589e-887c-a3ebf12533d0', 'dictate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈdɪkˌteɪt/', 'audio/dictate.mp3', 'An order or command.', 'I must obey the dictates of my conscience.', 'Work & Career', 'ra lệnh, đọc chính tả', 'Một mệnh lệnh hoặc chỉ thị.', 'Tôi phải tuân theo những mệnh lệnh của lương tâm mình.'),
    ('fa0922b0-c309-5bdd-b0de-6f1c47869f75', '4513696e-efd4-589e-887c-a3ebf12533d0', 'engagement', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɪnˈɡeɪd͡ʒ.mənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/engagement-us.mp3', 'An appointment, especially to speak or perform.', 'The lecturer has three speaking engagements this week.', 'Work & Career', 'cuộc hẹn, sự tham gia', 'Một cuộc hẹn, đặc biệt để nói chuyện hoặc biểu diễn.', 'Giảng viên có ba cuộc hẹn nói chuyện trong tuần này.'),
    ('1be94b8a-955f-5474-87a4-cca75d8a8acf', '4513696e-efd4-589e-887c-a3ebf12533d0', 'execution', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌek.sɪˈkjuː.ʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/execution-us.mp3', 'The act, manner or style of executing (actions, maneuvers, performances).', 'The mission''s successful execution lifted the troops'' morale.', 'Work & Career', 'sự thực hiện', 'Hành động, cách thức hoặc phong cách thực hiện (hành động, thao tác, màn trình diễn).', 'Việc thực hiện thành công nhiệm vụ đã nâng cao tinh thần của binh lính.'),
    ('953b4ec6-3e8e-567c-b4f7-11fb1a9f50ed', '4513696e-efd4-589e-887c-a3ebf12533d0', 'inspect', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ɪnˈspɛkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/inspect-us.mp3', 'To examine critically or carefully; especially, to search out problems or determine condition; to scrutinize.', 'Inspect the system for leaks.', 'Work & Career', 'kiểm tra', 'Kiểm tra một cách phê bình hoặc cẩn thận; đặc biệt, để tìm ra vấn đề hoặc xác định tình trạng; để xem xét kỹ lưỡng.', 'Kiểm tra hệ thống để tìm rò rỉ.'),
    ('d39da15a-6a34-5327-9421-8e65b3feb96f', '4513696e-efd4-589e-887c-a3ebf12533d0', 'inspection', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɪnˈspɛkʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/inspection-us.mp3', 'The act of examining something, often closely.', 'Upon closer inspection, the animal turned out to be a dolphin, not a shark!', 'Work & Career', 'sự kiểm tra', 'Hành động kiểm tra một cái gì đó, thường là kỹ lưỡng.', 'Khi kiểm tra kỹ hơn, con vật hóa ra là một con cá heo, không phải cá mập!'),
    ('f71431d2-cd1c-552b-86b4-1489fc71f000', '4513696e-efd4-589e-887c-a3ebf12533d0', 'memo', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈmɛməʊ̯/', 'audio/memo.mp3', 'A short note; a memorandum.', 'I made sure to memo him about the client''s complaints.', 'Work & Career', 'bản ghi nhớ', 'Một ghi chú ngắn; một bản ghi nhớ.', 'Tôi đã chắc chắn gửi bản ghi nhớ cho anh ta về những khiếu nại của khách hàng.'),
    ('803ec288-014c-5ca7-bf62-0b114f35f386', '4513696e-efd4-589e-887c-a3ebf12533d0', 'mining', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈmaɪnɪŋ/', 'audio/mining.mp3', 'To remove (ore) from the ground.', 'gold mining', 'Work & Career', 'khai thác mỏ', 'Loại bỏ (quặng) khỏi lòng đất.', 'khai thác vàng'),
    ('3742c10e-aa3e-5b16-a542-f6fd21bd5210', '4513696e-efd4-589e-887c-a3ebf12533d0', 'oversee', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/əʊvə(ɹ)siː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/oversee-uk.mp3', 'To survey, look at something in a wide angle.', 'It is congress''s duty to oversee the spending of federal funds.', 'Work & Career', 'giám sát', 'Quan sát, nhìn cái gì đó ở góc rộng.', 'Nhiệm vụ của quốc hội là giám sát việc chi tiêu ngân sách liên bang.'),
    ('c3889d54-07cb-5a8f-8af0-bfa0af496e2a', '4513696e-efd4-589e-887c-a3ebf12533d0', 'productive', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/pɹəˈdʌktɪv/', 'audio/productive.mp3', 'Capable of producing something, especially in abundance; fertile.', 'a productive set', 'Work & Career', 'hiệu quả', 'Có khả năng sản xuất ra thứ gì đó, đặc biệt là với số lượng dồi dào; màu mỡ.', 'một tập hợp hiệu quả'),
    ('03186a11-ef6b-5960-8307-3230b50d2f5f', '4513696e-efd4-589e-887c-a3ebf12533d0', 'productivity', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌpɹɒdʌkˈtɪvəti/', 'audio/productivity.mp3', 'The state of being productive, fertile or efficient', 'You can see the computer age everywhere but in the productivity statistics.', 'Work & Career', 'năng suất', 'Trạng thái có năng suất, màu mỡ hoặc hiệu quả.', 'Bạn có thể thấy thời đại máy tính ở khắp mọi nơi nhưng không thấy trong các số liệu năng suất.'),
    ('ef16aaa2-4a48-583e-b0d0-84fc21bff681', '4513696e-efd4-589e-887c-a3ebf12533d0', 'resume', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ɹəˈzjuːm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/resume-1-au.mp3', 'To take back possession of (something).', 'We will resume this discussion tomorrow at nine.', 'Work & Career', 'tiếp tục', 'Lấy lại quyền sở hữu (một thứ gì đó).', 'Chúng ta sẽ tiếp tục thảo luận vấn đề này vào ngày mai lúc chín giờ.'),
    ('b4f89bad-ca90-57d6-9065-15bb2271f05f', '4513696e-efd4-589e-887c-a3ebf12533d0', 'submission', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/səbˈmɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/submission-1-us.mp3', 'The act of submitting or yielding; surrender.', 'Any submissions received after Friday will have marks deducted for lateness.', 'Work & Career', 'sự nộp bài', 'Hành động nộp hoặc nhượng bộ; đầu hàng.', 'Bất kỳ bài nộp nào nhận được sau thứ Sáu sẽ bị trừ điểm vì trễ hạn.'),
    ('e9db79ae-9ce5-5de1-9858-8526aa0bb9a1', '4513696e-efd4-589e-887c-a3ebf12533d0', 'successor', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/səkˈsɛsə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/successor-us.mp3', 'A person or thing that immediately follows another in holding an office or title.', 'George W. Bush was successor to Bill Clinton as President of the US.', 'Work & Career', 'người kế nhiệm', 'Một người hoặc vật ngay lập tức kế nhiệm người khác trong việc nắm giữ chức vụ hoặc danh hiệu.', 'George W. Bush là người kế nhiệm Bill Clinton làm Tổng thống Hoa Kỳ.'),
    ('69473fb0-1f8a-5732-8b18-b095b446e40e', '4513696e-efd4-589e-887c-a3ebf12533d0', 'superior', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/suːˈpɪəɹi.ə(ɹ)/', 'audio/superior.mp3', 'A person of higher rank or quality.', 'Rebecca had always thought shorts were far superior to pants, as they didn''t constantly make her legs itch.', 'Work & Career', 'cấp trên', 'Một người có cấp bậc hoặc chất lượng cao hơn.', 'Rebecca luôn nghĩ quần short vượt trội hơn hẳn quần dài, vì chúng không liên tục làm chân cô ngứa.'),
    ('3b7f53c7-7f5c-5ad1-9838-f9b2404a57a8', '4513696e-efd4-589e-887c-a3ebf12533d0', 'supervision', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌs(j)uːpəˈvɪʒən/', 'audio/supervision.mp3', 'The act or instance of supervising.', 'Under his parents'' supervision he drilled the holes in the wood.', 'Work & Career', 'sự giám sát', 'Hành động hoặc trường hợp giám sát.', 'Dưới sự giám sát của bố mẹ, cậu bé khoan các lỗ trên gỗ.'),
    ('96495594-3202-5a34-b361-2f1389be5615', '4513696e-efd4-589e-887c-a3ebf12533d0', 'suspension', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/səˈspɛnʃən/', 'audio/suspension.mp3', 'The act of suspending, or the state of being suspended.', 'suspension from a hook', 'Work & Career', 'sự treo, đình chỉ', 'Hành động tạm ngừng, hoặc trạng thái bị tạm ngừng.', 'treo từ một cái móc'),
    ('9c9ba91f-8fd5-553d-a4f8-c8c0a4e9e4c1', '4513696e-efd4-589e-887c-a3ebf12533d0', 'terminate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈtɜːmɪneɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/terminate-uk.mp3', 'To end, especially in an incomplete state.', 'to terminate a surface by a line', 'Work & Career', 'chấm dứt', 'Kết thúc, đặc biệt là trong một trạng thái chưa hoàn thành.', 'kết thúc một bề mặt bằng một đường thẳng'),
    ('75f0d8ff-7740-5274-b0c1-9ce2113ec1f9', '4513696e-efd4-589e-887c-a3ebf12533d0', 'coordinate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, NULL, 'audio/coordinate.mp3', 'A number representing the position of a point along a line, arc, or similar one-dimensional figure.', 'Give me your coordinates and we''ll come and rescue you.', 'Work & Career', 'phối hợp, tọa độ', 'Một con số đại diện cho vị trí của một điểm dọc theo một đường, cung, hoặc hình một chiều tương tự.', 'Cho tôi tọa độ của bạn và chúng tôi sẽ đến giải cứu bạn.'),
    ('6bc18903-d16f-53fe-bdde-5d5bcae5d621', '4513696e-efd4-589e-887c-a3ebf12533d0', 'empower', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, NULL, 'audio/empower.mp3', 'To give permission, power, or the legal right to do something.', 'John found that starting up his own business empowered him greatly in social situations.', 'Work & Career', 'trao quyền', 'Cho phép, trao quyền lực, hoặc quyền hợp pháp để làm điều gì đó.', 'John nhận thấy việc bắt đầu kinh doanh riêng đã trao cho anh rất nhiều quyền trong các tình huống xã hội.'),
    ('d95331fc-03be-531e-a02a-dd2a808faca0', '4513696e-efd4-589e-887c-a3ebf12533d0', 'organizational', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, NULL, 'audio/organizational.mp3', 'Of, relating to, or produced by an organization.', 'He lacks organizational skills.', 'Work & Career', 'thuộc tổ chức', 'Thuộc, liên quan đến, hoặc được tạo ra bởi một tổ chức.', 'Anh ấy thiếu kỹ năng tổ chức.'),
    ('a19b7d11-5d72-5936-b1d4-274d25871a1d', '4513696e-efd4-589e-887c-a3ebf12533d0', 'supervise', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, NULL, 'audio/supervise.mp3', 'To oversee or direct a task or organization.', 'Without someone to supervise them, the group will lack direction.', 'Work & Career', 'giám sát', 'Giám sát hoặc chỉ đạo một nhiệm vụ hoặc tổ chức.', 'Nếu không có ai giám sát họ, nhóm sẽ thiếu định hướng.'),
    ('f75f7106-7f17-598f-9f21-746e211ae2f0', '4513696e-efd4-589e-887c-a3ebf12533d0', 'administrative', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ədˈmɪ.nɪs.tɹəˌtɪv/', 'audio/administrative.mp3', 'Of or relating to administering or administration.', NULL, 'Work & Career', 'hành chính', 'Thuộc hoặc liên quan đến việc quản lý hoặc hành chính.', NULL),
    ('34d0848f-aa85-5fbc-96a0-4ac985fbbe93', '4513696e-efd4-589e-887c-a3ebf12533d0', 'administrator', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ədˈmɪnɪstɹeɪtə/', 'audio/administrator.mp3', 'One who administers affairs; one who directs, manages, executes, or dispenses, whether in civil, judicial, political, or ecclesiastical affairs; a manager', NULL, 'Work & Career', 'quản trị viên', 'Người quản lý công việc; người chỉ đạo, quản lý, thực thi hoặc phân phối, dù trong công việc dân sự, tư pháp, chính trị hay giáo hội; một nhà quản lý', NULL),
    ('ddf5ab86-4d06-5bcd-bd6d-5d098e46d64b', '4513696e-efd4-589e-887c-a3ebf12533d0', 'aide', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/eɪd/', 'audio/aide.mp3', 'An assistant.', NULL, 'Work & Career', 'trợ lý', 'Một người trợ giúp.', NULL),
    ('903db970-68e3-55db-91c0-f7ba3c8346b7', '4513696e-efd4-589e-887c-a3ebf12533d0', 'appoint', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/əˈpɔɪnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/appoint-uk.mp3', 'To set, fix or determine (a time or place for something such as a meeting, or the meeting itself) by authority or agreement.', NULL, 'Work & Career', 'bổ nhiệm, chỉ định', 'Đặt, ấn định hoặc quyết định (thời gian hoặc địa điểm cho việc gì đó như một cuộc họp, hoặc chính cuộc họp đó) bằng thẩm quyền hoặc thỏa thuận.', NULL),
    ('0535848e-f1c3-523c-9fe9-2de152d1f4c5', '4513696e-efd4-589e-887c-a3ebf12533d0', 'capability', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/keɪpəˈbɪləti/', 'audio/capability.mp3', 'The power or ability to generate an outcome', NULL, 'Work & Career', 'khả năng, năng lực', 'Sức mạnh hoặc khả năng tạo ra một kết quả', NULL),
    ('c962df8e-cbbc-5b2c-99b2-016fbc35ca87', '4513696e-efd4-589e-887c-a3ebf12533d0', 'consultation', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌkɒnsl̩ˈteɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/consultation-uk.mp3', 'The act of consulting.', NULL, 'Work & Career', 'sự tham vấn', 'Hành động tham khảo ý kiến.', NULL),
    ('8c185eaa-53ff-5f5f-9c8e-c4c5e669da77', '4513696e-efd4-589e-887c-a3ebf12533d0', 'contractor', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkɒnˌtɹæk.tə(ɹ)/', 'audio/contractor.mp3', 'A person or company that builds or improves buildings.', NULL, 'Work & Career', 'nhà thầu', 'Một người hoặc công ty xây dựng hoặc cải tạo các tòa nhà.', NULL),
    ('5cf8e5ea-5f81-5fcd-8b58-19ab311a8db2', '4513696e-efd4-589e-887c-a3ebf12533d0', 'cooperate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/koʊˈɒpəɹeɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cooperate-uk.mp3', 'To work or act together, especially for a common purpose or benefit.', NULL, 'Work & Career', 'hợp tác', 'Làm việc hoặc hành động cùng nhau, đặc biệt vì mục đích hoặc lợi ích chung.', NULL),
    ('b245fe13-7a7f-5362-b930-86502f7a162f', '4513696e-efd4-589e-887c-a3ebf12533d0', 'delegation', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/dɛlɪˈɡeɪʃən/', 'audio/delegation.mp3', 'An act of delegating.', NULL, 'Work & Career', 'phái đoàn, ủy quyền', 'Hành động ủy quyền.', NULL),
    ('d47ba86a-e595-54d6-b428-5648ec821b12', '4513696e-efd4-589e-887c-a3ebf12533d0', 'deployment', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/dɪˈplɔɪmənt/', 'audio/deployment.mp3', 'An arrangement or classification of things.', NULL, 'Work & Career', 'sự triển khai', 'Một sự sắp xếp hoặc phân loại sự vật.', NULL),
    ('2a45d890-db9b-516b-9c7b-33994ec1e676', '4513696e-efd4-589e-887c-a3ebf12533d0', 'dismissal', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '[dɪsˈmɪsəɫ]', 'audio/dismissal.mp3', 'The act of sending someone away.', NULL, 'Work & Career', 'sự sa thải, giải tán', 'Hành động cho ai đó đi.', NULL),
    ('1da45c6e-e263-5034-8d5e-32e09c719319', '4513696e-efd4-589e-887c-a3ebf12533d0', 'endeavour', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɪnˈdɛv.ə/', 'audio/endeavour.mp3', 'A sincere attempt; a determined or assiduous effort towards a specific goal; assiduous or persistent activity.', NULL, 'Work & Career', 'nỗ lực', 'Một nỗ lực chân thành; một nỗ lực kiên định hoặc chăm chỉ hướng tới một mục tiêu cụ thể; hoạt động chăm chỉ hoặc bền bỉ.', NULL),
    ('88f03cb0-3bd6-53bf-80cd-7ad80fabcb0e', '4513696e-efd4-589e-887c-a3ebf12533d0', 'forge', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/fɔːd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/forge-uk.mp3', 'Furnace or hearth where metals are heated prior to hammering them into shape.', NULL, 'Work & Career', 'rèn', 'Lò hoặc bếp lò nơi kim loại được nung nóng trước khi rèn thành hình.', NULL),
    ('a4b0ea93-180a-5a8c-bdb2-729b61933271', '4513696e-efd4-589e-887c-a3ebf12533d0', 'personnel', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/-el/', 'audio/personnel.mp3', 'Employees; office staff.', NULL, 'Work & Career', 'nhân viên', 'Người lao động; nhân viên văn phòng.', NULL),
    ('30e33a3e-2560-5f91-83ac-c2e509c595fa', '4513696e-efd4-589e-887c-a3ebf12533d0', 'practitioner', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/pɹækˈtɪʃənə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/practitioner-uk.mp3', 'A person who practices a profession or art, especially law or medicine.', NULL, 'Work & Career', 'người hành nghề', 'Một người hành nghề hoặc nghệ thuật, đặc biệt là luật hoặc y học.', NULL),
    ('9e7262a9-5765-5690-8f9f-22d7ceba52ae', '4513696e-efd4-589e-887c-a3ebf12533d0', 'predecessor', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈpɹiːdɪsɛsɚ/', 'audio/predecessor.mp3', 'One who precedes; one who has preceded another in any state, position, office, etc.; one whom another follows or comes after, in any office or position.', NULL, 'Work & Career', 'người tiền nhiệm', 'Người đi trước; người đã đi trước người khác trong bất kỳ chức vụ, vị trí, văn phòng, v.v.; người mà người khác theo sau hoặc kế thừa, trong bất kỳ chức vụ hoặc vị trí nào.', NULL),
    ('3c6f9c08-1cbc-553f-9c9d-ed35eaa502a5', '4513696e-efd4-589e-887c-a3ebf12533d0', 'resignation', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɹɛzɪɡˈneɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/resignation-us.mp3', 'The act of resigning.', NULL, 'Work & Career', 'sự từ chức', 'Hành động từ chức.', NULL)
