INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('ab57e57c-37e8-55c0-a412-05a46e23e6d7', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'aesthetic', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/iːs.ˈθe.tɪk/', 'audio/aesthetic.mp3', 'The study of art or beauty.', 'Her most recent works have this quirky, half-serious 90''s teen culture-inspired aesthetic.', 'Arts & Entertainment', 'thẩm mỹ', 'Việc nghiên cứu nghệ thuật hoặc cái đẹp.', 'Các tác phẩm gần đây nhất của cô ấy có phong cách thẩm mỹ lập dị, nửa nghiêm túc lấy cảm hứng từ văn hóa tuổi teen thập niên 90 này.'),
    ('32c4956a-9e94-54a6-84dd-7dc7065a5656', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'applaud', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/əˈplɔːd/', 'audio/applaud.mp3', 'Applause; applauding.', 'After the performance, the audience applauded for five minutes.', 'Arts & Entertainment', 'vỗ tay, tán thưởng', 'Tiếng vỗ tay; sự vỗ tay tán thưởng.', 'Sau buổi biểu diễn, khán giả vỗ tay tán thưởng trong năm phút.'),
    ('3c67e30f-5b8a-59b2-902e-c0f2e30bbae2', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'backdrop', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈbæk.dɹɒp/', 'audio/backdrop.mp3', 'A decorated cloth hung at the back of a stage.', 'Against a backdrop of falling interest rates, the new savings account is looking less appealing.', 'Arts & Entertainment', 'phông nền', 'Một tấm vải trang trí treo ở phía sau sân khấu.', 'Trong bối cảnh lãi suất giảm, tài khoản tiết kiệm mới trông kém hấp dẫn hơn.'),
    ('e01221d5-b7ff-5d8e-baf3-c397f1537084', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'biography', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/baɪˈɒɡɹəfi/', 'audio/biography.mp3', 'A person''s life story, especially one published.', 'There are many biographies of Benjamin Franklin.', 'Arts & Entertainment', 'tiểu sử', 'Câu chuyện cuộc đời của một người, đặc biệt là một cuốn được xuất bản.', 'Có nhiều tiểu sử về Benjamin Franklin.'),
    ('999e042f-fba5-5143-a2e0-2e21f733d32f', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'canvas', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkæn.vəs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/canvas-us.mp3', 'A type of coarse cloth, woven from hemp, useful for making sails and tents or as a surface for paintings.', 'The author takes rural midwestern life as a canvas for a series of tightly woven character studies.', 'Arts & Entertainment', 'vải bạt, toan vẽ', 'Một loại vải thô, dệt từ sợi gai dầu, hữu ích để làm buồm và lều hoặc làm bề mặt cho tranh vẽ.', 'Tác giả lấy cuộc sống nông thôn vùng Trung Tây làm bối cảnh cho một loạt nghiên cứu nhân vật được dệt chặt chẽ.'),
    ('03f7baf1-ed83-541b-a0df-07da323a569f', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'clash', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/klaʃ/', 'audio/clash.mp3', 'A loud sound, like the crashing together of metal objects.', 'I heard a clash from the kitchen, and rushed in to find the cat had knocked over some pots and pans.', 'Arts & Entertainment', 'tiếng va chạm', 'Một âm thanh lớn, như tiếng các vật thể kim loại đập vào nhau.', 'Tôi nghe thấy tiếng va chạm từ nhà bếp, và chạy vào thấy con mèo đã làm đổ một số nồi và chảo.'),
    ('7a389f90-e2e5-50ab-b95a-41bf6a1b4660', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'creator', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/kɹiːˈeɪtə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/creator-uk.mp3', 'Something or someone which creates or makes something.', 'Kenneth E. Iverson was the creator of APL.', 'Arts & Entertainment', 'người sáng tạo', 'Thứ gì đó hoặc ai đó tạo ra hoặc làm ra thứ gì đó.', 'Kenneth E. Iverson là người sáng tạo ra APL.'),
    ('ae3660d4-8a47-599e-9594-954429827b50', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'cutting', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkʌtɪŋ/', 'audio/cutting.mp3', '(heading) To incise, to cut into the surface of something.', 'After the actors read their lines, the director yelled, "Cut!"', 'Arts & Entertainment', 'cắt, đoạn cắt', '(Tiêu đề) Để rạch, để cắt vào bề mặt của thứ gì đó.', 'Sau khi các diễn viên đọc lời thoại, đạo diễn hét lên, "Cắt!"'),
    ('c6bf8d1a-6a49-5d49-bc74-d25b27363c92', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'debut', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/dəˈbʉː/', 'audio/debut.mp3', 'A performer''s first performance to the public, in sport, the arts or some other area.', 'Since making its debut two years ago, the program has gained cult status.', 'Arts & Entertainment', 'ra mắt', 'Buổi biểu diễn đầu tiên của một nghệ sĩ trước công chúng, trong thể thao, nghệ thuật hoặc lĩnh vực khác.', 'Kể từ khi ra mắt hai năm trước, chương trình đã đạt được trạng thái được hâm mộ cuồng nhiệt.'),
    ('2d80334f-98b7-5745-b437-509e1d05f3f4', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'distort', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/dɪsˈtɔːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/distort-uk.mp3', 'To bring something out of shape, to misshape.', 'In their articles, journalists sometimes distort the truth.', 'Arts & Entertainment', 'bóp méo, làm biến dạng', 'Làm cho cái gì đó biến dạng, làm méo mó.', 'Trong các bài báo của mình, các nhà báo đôi khi bóp méo sự thật.'),
    ('f8490e54-c621-5850-a2ec-edb86b4ef43c', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'engaging', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ɪnˈɡeɪd͡ʒɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/engaging-us.mp3', '(heading) To interact socially.', 'I found the first of the Harry Potter books a very engaging read.', 'Arts & Entertainment', 'hấp dẫn, thu hút', '(tiêu đề) Tương tác xã hội.', 'Tôi thấy cuốn sách đầu tiên của Harry Potter là một tác phẩm rất hấp dẫn.'),
    ('6c123c91-0e59-59d3-b14a-1a6d428fe00e', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'flourish', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈflʌ.ɹɪʃ/', 'audio/flourish.mp3', 'A dramatic gesture such as the waving of a flag.', 'With many flourishes of the captured banner, they marched down the avenue.', 'Arts & Entertainment', 'phô trương', 'Một cử chỉ kịch tính như vẫy cờ.', 'Với nhiều động tác phô trương của lá cờ bị bắt, họ diễu hành xuống đại lộ.'),
    ('5be6f446-65d5-5b67-a212-35348dcfdfd7', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'harmony', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈhɑːməni/', 'audio/harmony.mp3', 'Agreement or accord.', 'a harmony of the Gospels', 'Arts & Entertainment', 'sự hài hòa', 'Sự đồng ý hoặc phù hợp.', 'sự hài hòa của các Sách Phúc Âm'),
    ('d55b4dcf-7b20-557c-b5c1-c96e5f19a14a', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'haunt', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/hænt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/haunt-uk.mp3', 'A place at which one is regularly found; a habitation or hangout.', 'I went back the town I used to live and visited all my old haunts.', 'Arts & Entertainment', 'ám ảnh', 'Một nơi mà người ta thường xuyên xuất hiện; nơi ở hoặc nơi lui tới.', 'Tôi trở lại thị trấn tôi từng sống và thăm tất cả những nơi tôi thường lui tới ngày xưa.'),
    ('b07193cd-bf4f-5086-a8df-281b929faa9a', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'heighten', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈhaɪtən/', 'audio/heighten.mp3', 'To make high; to raise higher; to elevate.', 'to heighten a flavor or a tint', 'Arts & Entertainment', 'tăng cường', 'Làm cho cao; nâng cao hơn; nâng lên.', 'để tăng cường hương vị hoặc sắc thái'),
    ('80a3046f-2e24-5d53-9088-a87c00b35485', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'inspiration', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɪnspɨˈɹeɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/inspiration-us.mp3', 'The drawing of air into the lungs, accomplished in mammals by elevation of the chest walls and flattening of the diaphragm, as part of the act of respiration.', 'She was waiting for inspiration to write a book.', 'Arts & Entertainment', 'cảm hứng', 'Việc hít không khí vào phổi, được thực hiện ở động vật có vú bằng cách nâng thành ngực và làm phẳng cơ hoành, như một phần của hành động hô hấp.', 'Cô ấy đang chờ đợi cảm hứng để viết một cuốn sách.'),
    ('72d761a6-3e21-5e0d-ae62-6c16710160cc', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'ironic', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/aɪˈɹɒn.ɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ironic-uk.mp3', 'Characterized by or constituting (any kind of) irony.', 'It''s ironic to have a blizzard in the middle of the summer.', 'Arts & Entertainment', 'mỉa mai', 'Được đặc trưng bởi hoặc cấu thành (bất kỳ loại) sự mỉa mai nào.', 'Thật mỉa mai khi có một trận bão tuyết giữa mùa hè.'),
    ('cf364912-d203-57e0-b7e8-4e9a6953aea5', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'magical', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈmædʒɪkəl/', 'audio/magical.mp3', 'Of or relating to magic.', 'The fireworks created a magical atmosphere in that beautiful summer night.', 'Arts & Entertainment', 'kỳ diệu', 'Thuộc hoặc liên quan đến ma thuật.', 'Pháo hoa tạo ra một bầu không khí kỳ diệu trong đêm hè đẹp trời đó.'),
    ('f4ee1fd8-b1ca-5b83-8991-93f11895dbb5', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'memoir', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈmɛmˌwɑː/', 'audio/memoir.mp3', 'An autobiography; a book describing the personal experiences of an author.', 'When I retire, I''m going to write my memoirs.', 'Arts & Entertainment', 'hồi ký', 'Một cuốn tự truyện; một cuốn sách mô tả những trải nghiệm cá nhân của tác giả.', 'Khi nghỉ hưu, tôi sẽ viết hồi ký của mình.'),
    ('d199abc0-ff57-52b5-b26b-548de38302e5', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'patron', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈpeɪ.tɹən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/patron-us.mp3', 'One who protects or supports; a defender or advocate.', 'This car park is for patrons only.', 'Arts & Entertainment', 'người bảo trợ', 'Người bảo vệ hoặc hỗ trợ; một người bảo vệ hoặc người ủng hộ.', 'Bãi đỗ xe này chỉ dành cho khách hàng.'),
    ('f32dfcfb-2d0c-501f-917b-24d05d7b002f', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'portray', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/pɔɹˈtɹeɪ/', 'audio/portray.mp3', 'To paint or draw the likeness of.', 'I will portray a king on horseback.', 'Arts & Entertainment', 'miêu tả', 'Vẽ hoặc phác họa chân dung của.', 'Tôi sẽ miêu tả một vị vua trên lưng ngựa.'),
    ('9229c697-7bc8-54ec-8fce-b1c1ff7f1940', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'render', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈɹɛn.də/', 'audio/render.mp3', 'Stucco or plaster applied to walls (mostly to outside masonry walls).', 'A low-resolution render might look blocky.', 'Arts & Entertainment', 'kết xuất', 'Stucco hoặc thạch cao được áp dụng cho tường (chủ yếu cho tường xây bên ngoài).', 'Một bản kết xuất độ phân giải thấp có thể trông lổn nhổn.'),
    ('af40a8f0-6528-5171-bfe8-f84abcff6829', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'representation', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌɹɛp.ɹə.zɛn.ˈteɪ.ʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/representation-us.mp3', 'That which represents something else.', 'The Venus of Willendorf was an early representation of the female body.', 'Arts & Entertainment', 'sự đại diện', 'Cái đại diện cho một cái gì đó khác.', 'Tượng Vệ nữ Willendorf là một đại diện sớm của cơ thể phụ nữ.'),
    ('fa66978e-c7b9-5095-8531-6714b549fd07', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'restoration', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɹɛstəˈɹeɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/restoration-us.mp3', 'The process of bringing an object back to its original state; the process of restoring something.', 'The restoration of this medieval church involved undoing all the Victorian modifications.', 'Arts & Entertainment', 'sự phục hồi', 'Quá trình đưa một vật thể trở lại trạng thái ban đầu; quá trình khôi phục một thứ gì đó.', 'Việc phục hồi nhà thờ thời trung cổ này liên quan đến việc hủy bỏ tất cả các sửa đổi thời Victoria.'),
    ('6f4caa5c-a291-5f5b-bd94-65ff0ea83392', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'revival', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɹɪˈvaɪvəl/', 'audio/revival.mp3', 'The act of reviving, or the state of being revived', 'the revival of hot pants', 'Arts & Entertainment', 'sự phục hưng', 'Hành động phục hồi, hoặc trạng thái được phục hồi', 'sự hồi sinh của quần short nóng bỏng'),
    ('6453f832-239e-5e53-9494-1ec6f2de1130', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'serial', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈsɪəɹiːəɫ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/serial-au.mp3', 'A work, such as a work of fiction, published in installments, often numbered and without a specified end.', 'Go to these sites for serials, cracks and keygens.', 'Arts & Entertainment', 'nhiều kỳ, loạt', 'Một tác phẩm, chẳng hạn như một tác phẩm hư cấu, được xuất bản thành nhiều phần, thường được đánh số và không có kết thúc được chỉ định.', 'Truy cập các trang web này để tìm các bản nhiều kỳ, bẻ khóa và keygen.'),
    ('124515b1-cf64-51aa-a34f-dba91dc123b7', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'sketch', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/skɛtʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sketch-us.mp3', 'A rapidly executed freehand drawing that is not intended as a finished work, often consisting of a multitude of overlapping lines.', 'to keep sketch', 'Arts & Entertainment', 'bản phác thảo', 'Một bản vẽ nhanh bằng tay không nhằm mục đích là một tác phẩm hoàn chỉnh, thường bao gồm nhiều đường chồng chéo lên nhau.', 'để giữ bản phác thảo'),
    ('97ad6ad8-131e-581f-b76a-bd7dee3686ef', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'slam', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/slæm/', 'audio/slam.mp3', 'A sudden impact or blow.', 'I don''t mean this as a slam, but you can be really impatient sometimes.', 'Arts & Entertainment', 'đập mạnh, chỉ trích', 'Một tác động hoặc cú đánh đột ngột.', 'Tôi không có ý chỉ trích, nhưng đôi khi bạn có thể thực sự thiếu kiên nhẫn.'),
    ('2cbd06b6-458b-587d-b465-a075848f815b', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'smash', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/smæʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/smash-us.mp3', 'The sound of a violent impact; a violent striking together.', 'I could hear the screech of the brakes, then the horrible smash of cars colliding.', 'Arts & Entertainment', 'đập vỡ, va mạnh', 'Âm thanh của một tác động mạnh; một sự va chạm dữ dội với nhau.', 'Tôi có thể nghe thấy tiếng phanh kít, rồi tiếng đâm kinh khủng của những chiếc xe va vào nhau.'),
    ('380fbc0b-9ab7-501b-b70f-5bb76ecbb529', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'snap', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/snæp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/snap-au.mp3', 'A quick breaking or cracking sound or the action of producing such a sound.', 'We took a few snaps of the old church before moving on.', 'Arts & Entertainment', 'bẻ gãy, chụp ảnh', 'Một âm thanh gãy hoặc nứt nhanh hoặc hành động tạo ra âm thanh như vậy.', 'Chúng tôi chụp một vài bức ảnh của nhà thờ cũ trước khi đi tiếp.'),
    ('67c0b569-49d4-55af-95b5-710b1aed55cc', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'spectacle', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈspɛktəkl̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/spectacle-uk.mp3', 'An exciting or extraordinary scene, exhibition, performance etc.', 'The horse race was a thrilling spectacle.', 'Arts & Entertainment', 'cảnh tượng, màn trình diễn', 'Một cảnh tượng, triển lãm, buổi biểu diễn, v.v. thú vị hoặc phi thường.', 'Cuộc đua ngựa là một cảnh tượng ly kỳ.'),
    ('95bd7a98-ca68-50ff-90c0-5b797301855e', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'sustain', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/səˈsteɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sustain-us.mp3', 'A mechanism which can be used to hold a note, as the right pedal on a piano.', 'The city came under sustained attack by enemy forces.', 'Arts & Entertainment', 'duy trì, ngân', 'Một cơ chế có thể được sử dụng để giữ một nốt nhạc, như bàn đạp bên phải trên đàn piano.', 'Thành phố bị tấn công liên tục bởi lực lượng địch.'),
    ('47cb1189-f48c-5a58-bd46-ea79c0fba503', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'verse', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈvɜːs/', 'audio/verse.mp3', 'A poetic form with regular meter and a fixed rhyme scheme.', 'Restoration literature is well known for its carefully constructed verse.', 'Arts & Entertainment', 'thơ', 'Một hình thức thơ với nhịp điệu đều đặn và cấu trúc vần cố định.', 'Văn học thời Phục hưng nổi tiếng với những bài thơ được xây dựng cẩn thận.'),
    ('18999c6f-3db7-53e8-a82a-bf3ae4192064', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'vocal', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈvəʊ.kəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/vocal-uk.mp3', 'A vocal sound; specifically, a purely vocal element of speech, unmodified except by resonance; a vowel or a diphthong; a tonic element; a tonic; distinguished from a subvocal, and a nonvocal', 'vocal problems', 'Arts & Entertainment', 'thanh nhạc', 'Một âm thanh bằng giọng nói; cụ thể, một yếu tố thuần túy bằng giọng nói của lời nói, không bị thay đổi ngoại trừ cộng hưởng; một nguyên âm hoặc một nguyên âm đôi; một yếu tố âm sắc; một âm sắc; phân biệt với âm phụ và âm không thanh', 'các vấn đề về giọng nói'),
    ('0c68eafd-d271-5e01-a953-501bc245fc5b', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'weave', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/wiːv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/weave-us.mp3', 'A type or way of weaving.', 'That rug has a very tight weave.', 'Arts & Entertainment', 'dệt', 'Một loại hoặc cách dệt.', 'Tấm thảm đó có kiểu dệt rất chặt.'),
    ('a42cce5f-aee0-5e9c-976f-5c9bdc19ee30', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'commentary', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, NULL, 'audio/commentary.mp3', 'A series of comments or annotations; especially, a book of explanations or expositions on the whole or a part of some other work', 'Caesar''s Commentaries on the Gallic War', 'Arts & Entertainment', 'bình luận', 'Một loạt các bình luận hoặc chú thích; đặc biệt là một cuốn sách giải thích hoặc trình bày về toàn bộ hoặc một phần của một tác phẩm khác', 'Bình luận của Caesar về Chiến tranh Gallic'),
    ('1e4d0797-ed58-5faa-86c1-a903d7bd38a1', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'ironically', 'C1', '["adv"]'::jsonb, '[{"pos": "adv", "level": "C1"}]'::jsonb, NULL, 'audio/ironically.mp3', '(manner) In an ironic manner; in a way displaying irony.', 'Ironically, the automated checkout system ended up costing more in repairs than the workers it was meant to replace.', 'Arts & Entertainment', 'một cách mỉa mai', '(cách thức) Một cách mỉa mai; theo cách thể hiện sự mỉa mai.', 'Thật mỉa mai, hệ thống thanh toán tự động cuối cùng lại tốn nhiều chi phí sửa chữa hơn số nhân công mà nó được thiết kế để thay thế.'),
    ('d5d9f0d3-2ade-56b3-ba4a-d16565901a99', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'rhetoric', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, NULL, 'audio/rhetoric.mp3', 'The art of using language, especially public speaking, as a means to persuade.', 'It’s only so much rhetoric.', 'Arts & Entertainment', 'hùng biện', 'Nghệ thuật sử dụng ngôn ngữ, đặc biệt là nói trước công chúng, như một phương tiện để thuyết phục.', 'Nó chỉ là nhiều lời hùng biện mà thôi.'),
    ('e96d4e14-3980-5865-b904-b3cdf49fb5bb', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'spotlight', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, NULL, 'audio/spotlight.mp3', 'A bright, directional light or lamp, especially one used to illuminate the focus or center of attention on a stage.', 'Some people enjoy the spotlight.', 'Arts & Entertainment', 'đèn sân khấu', 'Một ánh sáng hoặc đèn định hướng sáng, đặc biệt là loại được sử dụng để chiếu sáng trọng tâm hoặc trung tâm của sự chú ý trên sân khấu.', 'Một số người thích được chú ý.'),
    ('43504358-98d2-5678-8732-8baf2920a51a', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'symbolic', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, NULL, 'audio/symbolic.mp3', 'Pertaining to a symbol.', 'a symbolic gesture', 'Arts & Entertainment', 'tượng trưng', 'Thuộc về một biểu tượng.', 'một cử chỉ mang tính tượng trưng'),
    ('f093e2ae-8913-50b2-bf0e-b543e8090c2d', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'architectural', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˌɑɹkɪˈtɛktjəɹəl/', 'audio/architectural.mp3', 'Pertaining to architecture.', NULL, 'Arts & Entertainment', 'thuộc kiến trúc', 'Liên quan đến kiến trúc.', NULL),
    ('f88685e8-7209-5237-82d4-b21306e745f9', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'casino', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/kæˈsinoʊ/', 'audio/casino.mp3', 'A public building or room for entertainment, especially gambling.', NULL, 'Arts & Entertainment', 'sòng bạc', 'Một tòa nhà hoặc phòng công cộng dành cho giải trí, đặc biệt là đánh bạc.', NULL),
    ('79531d20-a5d3-57c0-877b-d93e201901e0', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'characterize', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈkæɹəktəɹaɪz/', 'audio/characterize.mp3', 'To depict someone or something a particular way (often negative).', NULL, 'Arts & Entertainment', 'đặc trưng hóa, mô tả', 'Miêu tả ai đó hoặc điều gì đó theo một cách cụ thể (thường mang nghĩa tiêu cực).', NULL),
    ('bf26596a-6eef-5a8e-b606-a624ac6beedf', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'columnist', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkɒ.lə.mɪst/', 'audio/columnist.mp3', 'A regular writer of a column, such as in a magazine or newspaper', NULL, 'Arts & Entertainment', 'người viết chuyên mục', 'Người viết thường xuyên một chuyên mục, chẳng hạn trên tạp chí hoặc báo.', NULL),
    ('03f39df3-32bc-583c-8b58-27be430acbca', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'commentator', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkɑmənˌteɪtəɹ/', 'audio/commentator.mp3', 'A person who comments; especially someone who is paid to give his/her opinions in the media about current affairs, sports, etc.', NULL, 'Arts & Entertainment', 'bình luận viên', 'Một người đưa ra bình luận; đặc biệt là người được trả tiền để đưa ra ý kiến trên các phương tiện truyền thông về thời sự, thể thao, v.v.', NULL),
    ('0f7f0560-026d-50c3-ac9a-8e8701037da1', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'composition', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˌkɒmpəˈzɪʃən/', 'audio/composition.mp3', 'The act of putting together; assembly.', NULL, 'Arts & Entertainment', 'sáng tác, cấu thành', 'Hành động đặt lại với nhau; lắp ráp.', NULL),
    ('8fea180a-16ac-5c52-b77c-7007977f79dc', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'depict', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/dɪˈpɪkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/depict-us.mp3', 'To render a representation of something, using words, sounds, images, or other means.', NULL, 'Arts & Entertainment', 'miêu tả, mô tả', 'Tạo ra một biểu diễn của một cái gì đó, sử dụng từ ngữ, âm thanh, hình ảnh hoặc các phương tiện khác.', NULL),
    ('69c79d39-fc62-5638-81f7-da6e5be1af29', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'duo', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈdjuː.əʊ/', 'audio/duo.mp3', 'Two people who work or collaborate together as partners; especially, those who perform music together.', NULL, 'Arts & Entertainment', 'bộ đôi', 'Hai người làm việc hoặc cộng tác cùng nhau như đối tác; đặc biệt, những người biểu diễn âm nhạc cùng nhau.', NULL),
    ('9854958a-c709-5ff7-bb5c-bc7c04f83c03', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'imagery', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/-ədʒɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/imagery-us.mp3', 'The work of one who makes images or visible representation of objects.', NULL, 'Arts & Entertainment', 'hình ảnh', 'Công việc của người tạo ra hình ảnh hoặc đại diện hữu hình của các vật thể.', NULL),
    ('f94812b6-234f-54b6-947e-baf4628f5f5d', '6d48a424-57e3-5df6-81aa-828d60ddf42c', 'irony', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈaɪə.ɹən.i/', 'audio/irony.mp3', 'A statement that, when taken in context, may actually mean something different from, or the opposite of, what is written literally; the use of words expressing something other than their literal intention, often in a humorous context.', NULL, 'Arts & Entertainment', 'sự mỉa mai', 'Một tuyên bố mà, khi được hiểu trong ngữ cảnh, thực sự có thể mang nghĩa khác với, hoặc trái ngược với, nghĩa đen của nó; việc sử dụng từ ngữ diễn đạt điều gì đó khác với ý định nghĩa đen của chúng.', NULL)
