    ('d5432c09-79ed-5091-96c8-bf39cbb25fd0', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'ash', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/æʃ/', 'audio/ash.mp3', 'The solid remains of a fire.', 'Ash from a fireplace can restore minerals to your garden''s soil.', 'Nature & Environment', 'tro', 'Phần chất rắn còn lại sau một đám cháy.', 'Tro từ lò sưởi có thể khôi phục khoáng chất cho đất vườn của bạn.'),
    ('2e26ca7b-6ed8-59eb-8eb7-ca6909cc8fc5', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'beast', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/biːst/', 'audio/beast.mp3', 'Any animal other than a human; usually only applied to land vertebrates, especially large or dangerous four-footed ones.', 'That is a beast of a stadium.', 'Nature & Environment', 'thú vật', 'Bất kỳ động vật nào khác ngoài con người; thường chỉ áp dụng cho động vật có xương sống trên cạn, đặc biệt là những loài bốn chân lớn hoặc nguy hiểm.', 'Đó là một sân vận động khổng lồ.'),
    ('f13abd56-f1d8-51c2-8367-1f9dec18f9c9', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'boom', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/buːm/', 'audio/boom.mp3', 'A low-pitched, resonant sound, such as of an explosion.', 'The boom of the surf.', 'Nature & Environment', 'tiếng nổ', 'Âm thanh trầm, vang, chẳng hạn như của một vụ nổ.', 'Tiếng ầm ầm của sóng biển.'),
    ('df85d50e-5843-58ba-ba8d-b4800e26ca0d', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'breed', 'C1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "C1"}, {"pos": "n", "level": "C1"}]'::jsonb, '/bɹiːd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/breed-us.mp3', 'All animals or plants of the same species or subspecies.', 'a breed of animal', 'Nature & Environment', 'giống', 'Tất cả động vật hoặc thực vật cùng loài hoặc phân loài.', 'một giống động vật'),
    ('2d7254b7-aa03-5b5e-8837-b9dd5d461b63', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'buck', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/bʌk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/buck-au.mp3', 'A male deer, antelope, sheep, goat, rabbit, hare, and sometimes the male of other animals such as the hamster, ferret and shad.', 'Can I borrow five bucks?', 'Nature & Environment', 'con hươu đực', 'Một con hươu đực, linh dương, cừu, dê, thỏ, thỏ rừng, và đôi khi là con đực của các động vật khác như chuột hamster, chồn sương và cá shad.', 'Cho tôi mượn năm đô được không?'),
    ('948de61a-739b-5532-8079-5e33eeee6bab', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'burst', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/bɜːst/', 'audio/burst.mp3', 'An act or instance of bursting.', 'The bursts of the bombs could be heard miles away.', 'Nature & Environment', 'bùng nổ', 'Một hành động hoặc sự kiện bùng nổ.', 'Những tiếng nổ của bom có thể được nghe thấy từ cách đó hàng dặm.'),
    ('9d085f65-ec2b-52cb-8a32-12e8e6806abb', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'cattle', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈkæt(ə)l/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cattle-us.mp3', 'Domesticated bovine animals (cows, bulls, steers etc).', 'Do you want to raise cattle?', 'Nature & Environment', 'gia súc', 'Động vật nhai lại được thuần hóa (bò cái, bò đực, bò thiến, v.v.).', 'Bạn có muốn chăn nuôi gia súc không?'),
    ('3baee2e6-81a0-5a44-a799-54e34d56a721', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'cling', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈklɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cling-uk.mp3', 'Fruit (especially peach) whose flesh adheres strongly to the pit.', 'Seaweed clung to the anchor.', 'Nature & Environment', 'bám chặt', 'Trái cây (đặc biệt là đào) có phần thịt dính chặt vào hột.', 'Rong biển bám chặt vào mỏ neo.'),
