    ('a249858c-abcf-553d-9d7b-26feefadef49', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'ecological', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˌiːkəˈlɒd͡ʒɪkl̩/', 'audio/ecological.mp3', 'Relating to ecology, the interrelationships of organisms and their environment.', NULL, 'Nature & Environment', 'thuộc sinh thái', 'Liên quan đến sinh thái học, mối quan hệ tương hỗ giữa các sinh vật và môi trường của chúng.', NULL),
    ('1df147fe-5732-57fd-8f62-00a29d9a9346', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'mainland', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈmeɪ̪nlənd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mainland-us.mp3', 'The continent; the principal land, as distinguished from islands or a peninsula.', NULL, 'Nature & Environment', 'đất liền', 'Lục địa; vùng đất chính, để phân biệt với các đảo hoặc bán đảo.', NULL),
    ('903441b5-24dc-5113-be75-8b4ac6bd8c74', 'c1dc29d9-e21f-577d-b4c6-9aa7461b96e4', 'pathway', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈpæθˌweɪ/', 'audio/pathway.mp3', 'A footpath or other path or track.', NULL, 'Nature & Environment', 'đường mòn', 'Một lối đi bộ hoặc đường mòn khác.', NULL)
