INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('369ac749-466f-5d0d-a2e5-6756dbb77db2', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'adjacent', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/əˈdʒeɪ.sənt/', 'audio/adjacent.mp3', 'Something that lies next to something else, especially the side of a right triangle that is neither the hypotenuse nor the opposite.', 'Because the conference room is filled, we will have our meeting in the adjacent room.', 'Home & Living', 'liền kề', 'Thứ gì đó nằm cạnh thứ khác, đặc biệt là cạnh của tam giác vuông không phải là cạnh huyền hay cạnh đối.', 'Vì phòng hội nghị đã đầy, chúng tôi sẽ họp ở phòng liền kề.'),
    ('8310760c-07a9-5f44-b2fd-09bd9689f041', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'barrel', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈbæɹəl/', 'audio/barrel.mp3', 'A round vessel or cask, of greater length than breadth, and bulging in the middle, made of staves bound with hoops, and having flat ends or heads. Sometimes applied to a similar cylindrical container made of metal, usually called a drum.', 'a cracker barrel', 'Home & Living', 'thùng', 'Một thùng chứa hoặc thùng tròn, dài hơn rộng, và phình ra ở giữa, làm từ các thanh gỗ được buộc bằng vòng sắt, và có hai đầu phẳng. Đôi khi áp dụng cho một thùng chứa hình trụ tương tự.', 'thùng bánh quy giòn'),
    ('940991fb-d1aa-50bc-8119-178ff10529aa', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'beam', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/biːm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/beam-us.mp3', 'Any large piece of timber or iron long in proportion to its thickness, and prepared for use.', 'This ship has more beam than that one.', 'Home & Living', 'xà ngang', 'Bất kỳ thanh gỗ hoặc sắt lớn nào có chiều dài tương xứng với độ dày của nó, và đã được chuẩn bị để sử dụng.', 'Con tàu này có xà ngang rộng hơn con tàu kia.'),
    ('483359bb-f4f4-584f-ba6f-7e98de403863', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'bench', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/bɛntʃ/', 'audio/bench.mp3', 'A long seat with or without a back, found for example in parks and schools.', 'They sat on a park bench and tossed bread crumbs to the ducks and pigeons.', 'Home & Living', 'ghế dài', 'Một chiếc ghế dài có hoặc không có tựa lưng, được tìm thấy chẳng hạn trong công viên và trường học.', 'Họ ngồi trên một chiếc ghế dài trong công viên và ném vụn bánh mì cho vịt và bồ câu.'),
    ('ece57a30-8fdc-56e8-8bec-07237063fa92', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'blade', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/bleɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/blade-us.mp3', 'The sharp cutting edge of a knife, chisel, or other tool, a razor blade/sword.', 'Want to go blading with me later in the park?', 'Home & Living', 'lưỡi', 'Phần cắt sắc bén của dao, đục hoặc dụng cụ khác, lưỡi dao cạo/kiếm.', 'Muốn đi trượt patin với tôi sau ở công viên không?'),
    ('c560d2d4-b89a-579a-9b79-f9b873c3e425', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'chamber', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈtʃeɪmbə(ɹ)/', 'audio/chamber.mp3', 'A room or set of rooms, particularly:', 'The resolution, which speedily passed the Senate, was unable to gain a majority in the lower chamber.', 'Home & Living', 'phòng, buồng', 'Một phòng hoặc một nhóm phòng, cụ thể là:', 'Nghị quyết, vốn nhanh chóng được Thượng viện thông qua, đã không thể giành được đa số ở hạ viện.'),
    ('d30cd292-78bd-59c1-a6cd-fdb227f1d430', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'dispose', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/dɪˈspəʊz/', 'audio/dispose.mp3', 'The disposal or management of something.', 'I dispose of my trash in the garbage can.', 'Home & Living', 'vứt bỏ, sắp xếp', 'Việc vứt bỏ hoặc quản lý cái gì đó.', 'Tôi vứt rác của tôi vào thùng rác.'),
    ('5ce89d6b-4af5-56ee-b1ff-bc7971f918e8', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'drain', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/dɹeɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/drain-us.mp3', 'A conduit allowing liquid to flow out of an otherwise contained volume; a plughole (UK)', 'The drain in the kitchen sink is clogged.', 'Home & Living', 'cống thoát nước', 'Đường ống cho phép chất lỏng chảy ra khỏi một thể tích vốn được chứa; lỗ thoát nước.', 'Cống thoát nước ở bồn rửa bếp bị tắc.'),
    ('ae0380b9-a2ce-5d18-9f8e-a3a3162cb28f', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'fixture', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈfɪkstʃə/', 'audio/fixture.mp3', 'Something that is fixed in place, especially a permanent appliance or other item of personal property that is considered part of a house and is sold with it; compare fitting, furnishing.', 'The device is available in both handheld and fixtured models.', 'Home & Living', 'vật cố định, thiết bị', 'Thứ gì đó được cố định tại chỗ, đặc biệt là một thiết bị gia dụng vĩnh viễn hoặc đồ đạc cá nhân khác được coi là một phần của ngôi nhà và được bán cùng với nó; so sánh với fitting, furnishing.', 'Thiết bị có sẵn ở cả hai mẫu cầm tay và cố định.'),
    ('b62bec92-4051-5a00-ae5c-b0b786b3386c', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'handy', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈhæn.di/', 'https://api.dictionaryapi.dev/media/pronunciations/en/handy-1-us.mp3', 'Easy to use, useful.', 'Some people regard duct tape as a handy fix-all.', 'Home & Living', 'tiện dụng', 'Dễ sử dụng, hữu ích.', 'Một số người coi băng dính là một vật liệu tiện dụng để sửa mọi thứ.'),
    ('1b5da996-605a-599e-bf09-d0c73551fe81', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'interior', 'C1', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "C1"}, {"pos": "n", "level": "C1"}]'::jsonb, '/ɪnˈtɪəɹɪə/', 'audio/interior.mp3', 'The inside of a building, container, cavern, or other enclosed structure.', 'Sir Richard Burton explored far into the African interior.', 'Home & Living', 'nội thất', 'Bên trong của một tòa nhà, thùng chứa, hang động, hoặc cấu trúc có mái che khác.', 'Sir Richard Burton đã khám phá sâu vào vùng nội địa châu Phi.'),
    ('e10a84ff-ead7-5a25-a0b6-23f2fb03ff55', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'leak', 'C1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "C1"}, {"pos": "n", "level": "C1"}]'::jsonb, '/liːk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/leak-us.mp3', 'A crack, crevice, fissure, or hole which admits water or other fluid, or lets it escape.', 'a leak in a boat', 'Home & Living', 'rò rỉ', 'Vết nứt, kẽ hở, đường nứt hoặc lỗ cho phép nước hoặc chất lỏng khác lọt vào hoặc thoát ra.', 'một lỗ rò trên thuyền'),
    ('078658c7-c664-53a5-9683-75e4453d8ef0', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'lobby', 'C1', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "C1"}, {"pos": "v", "level": "C1"}]'::jsonb, '/lɒbi/', 'audio/lobby.mp3', 'An entryway or reception area; vestibule; passageway; corridor.', 'I had to wait in the lobby for hours before seeing the doctor.', 'Home & Living', 'sảnh', 'Lối vào hoặc khu vực tiếp tân; tiền sảnh; lối đi; hành lang.', 'Tôi đã phải đợi ở sảnh hàng giờ trước khi gặp bác sĩ.'),
    ('b1b979fd-e1ba-5af4-b655-2b4e173fb4fc', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'mill', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/mɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mill-us.mp3', 'A grinding apparatus for substances such as grains, seeds, etc.', 'Pepper has a stronger flavor when it is ground straight from a mill.', 'Home & Living', 'cối xay', 'Thiết bị nghiền cho các chất như ngũ cốc, hạt, v.v.', 'Hạt tiêu có hương vị mạnh hơn khi được xay trực tiếp từ cối xay.'),
    ('ce412d8c-9179-58b4-9f55-f57dcc8db3d9', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'nursery', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈnɜːsəɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/nursery-uk.mp3', 'A place where nursing or the raising of children is carried on.', 'Commerce is the nursery of seamen.', 'Home & Living', 'phòng trẻ em, vườn ươm', 'Một nơi mà việc chăm sóc hoặc nuôi dạy trẻ em được thực hiện.', 'Thương mại là vườn ươm của thủy thủ.'),
    ('1a9d9ea5-5eaf-5321-b139-6872eaa91d55', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'overlook', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/əʊvəˈlʊk/', 'audio/overlook.mp3', 'A vista or point that gives a beautiful view.', 'Our hotel room overlooks the lake.', 'Home & Living', 'nhìn ra', 'Một cảnh quan hoặc điểm cho một góc nhìn đẹp.', 'Phòng khách sạn của chúng tôi nhìn ra hồ.'),
    ('4bcf9f30-a80a-5c34-a205-cbc9b4483eee', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'pad', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/pæd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pad-au.mp3', 'A flattened mass of anything soft, to sit or lie on.', 'May 21, 2008, Austin American-Statesman', 'Home & Living', 'miếng đệm', 'Một khối phẳng của bất cứ thứ gì mềm, để ngồi hoặc nằm lên.', 'Ngày 21 tháng 5 năm 2008, Austin American-Statesman'),
    ('dbb8f00e-5ad0-517a-82eb-6127f15c9be6', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'patch', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/pætʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/patch-us.mp3', 'A piece of cloth, or other suitable material, sewed or otherwise fixed upon a garment to repair or strengthen it, especially upon an old garment to cover a hole.', 'His sleeves had patches on the elbows where different fabric had been sewn on to replace material that had worn away.', 'Home & Living', 'miếng vá', 'Một mảnh vải, hoặc vật liệu phù hợp khác, được khâu hoặc cố định lên quần áo để sửa chữa hoặc tăng cường nó, đặc biệt là trên quần áo cũ để che một lỗ hổng.', 'Tay áo của anh ấy có những miếng vá ở khuỷu tay, nơi vải khác đã được khâu vào để thay thế phần vải đã bị mòn.'),
    ('14f5453f-40bb-54e4-a628-64e73d661686', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'plug', 'C1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "C1"}, {"pos": "n", "level": "C1"}]'::jsonb, '/plʌɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/plug-us.mp3', 'A pronged connecting device which fits into a mating socket, especially an electrical one.', 'I pushed the plug back into the electrical socket and the lamp began to glow again.', 'Home & Living', 'phích cắm', 'Thiết bị kết nối có chân cắm vừa với ổ cắm tương ứng, đặc biệt là ổ cắm điện.', 'Tôi cắm phích cắm trở lại vào ổ điện và chiếc đèn bắt đầu sáng trở lại.'),
    ('854e05bf-a744-5cb3-8dec-92bb41c0c5e7', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'pole', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/pɔːl/', 'audio/pole.mp3', 'Originally, a stick; now specifically, a long and slender piece of metal or (especially) wood, used for various construction or support purposes.', 'Huck Finn poled that raft southward down the Mississippi because going northward against the current was too much work.', 'Home & Living', 'cây cột', 'Ban đầu là một cây gậy; bây giờ cụ thể, một thanh dài và mảnh bằng kim loại hoặc (đặc biệt) gỗ, được sử dụng cho các mục đích xây dựng hoặc hỗ trợ khác nhau.', 'Huck Finn chống cây sào đẩy chiếc bè đó về phía nam xuôi dòng Mississippi vì đi ngược dòng về phía bắc là quá vất vả.'),
    ('b31b249c-692c-5761-9d05-aa4e0fbab40f', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'pump', 'C1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "C1"}, {"pos": "n", "level": "C1"}]'::jsonb, '/pʌmp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pump-us.mp3', 'A device for moving or compressing a liquid or gas.', 'This pump can deliver 100 gallons of water per minute.', 'Home & Living', 'bơm', 'Thiết bị để di chuyển hoặc nén chất lỏng hoặc khí.', 'Máy bơm này có thể cung cấp 100 gallon nước mỗi phút.'),
    ('9f431dd2-ff22-5143-94be-c34281f3d3dd', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'rental', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈɹɛntəl/', 'audio/rental.mp3', 'Something that is rented.', 'It''s just a rental, so I don''t need to take very good care of it.', 'Home & Living', 'đồ cho thuê', 'Một thứ gì đó được thuê.', 'Nó chỉ là đồ thuê thôi, nên tôi không cần phải chăm sóc nó quá kỹ.'),
    ('12c09e7a-bd78-5886-b8c0-b856033128bd', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'rod', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɹɒd/', 'audio/rod.mp3', 'A straight, round stick, shaft, bar, cane, or staff.', 'When I hooked a snake and not a fish, I got so scared I dropped my rod in the water.', 'Home & Living', 'cần câu, que', 'Một cây gậy, trục, thanh, gậy hoặc cây trượng thẳng, tròn.', 'Khi tôi câu phải một con rắn chứ không phải cá, tôi sợ đến mức làm rơi cần câu xuống nước.'),
    ('96bab9f7-5705-534a-a783-ff7cc8ea9c77', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'sack', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/sæk/', 'audio/sack.mp3', 'A bag; especially a large bag of strong, coarse material for storage and handling of various commodities, such as potatoes, coal, coffee; or, a bag with handles used at a supermarket, a grocery sack; or, a small bag for small items, a satchel.', 'The American sack of salt is 215 pounds; the sack of wheat, two bushels. — McElrath.', 'Home & Living', 'bao tải, sa thải', 'Một cái túi; đặc biệt là một túi lớn bằng vật liệu thô, chắc chắn để lưu trữ và xử lý các mặt hàng khác nhau, chẳng hạn như khoai tây, than, cà phê; hoặc, một túi có tay cầm được sử dụng ở siêu thị, một túi tạp hóa;', 'Bao muối của Mỹ là 215 pound; bao lúa mì, hai giạ. — McElrath.'),
    ('685c160d-d303-512a-a178-c45dd26fe4a6', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'screw', 'C1', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "C1"}, {"pos": "n", "level": "C1"}]'::jsonb, '/skɹuː/', 'https://api.dictionaryapi.dev/media/pronunciations/en/screw-us.mp3', 'A device that has a helical function.', 'the skeleton screw (Caprella); the sand screw', 'Home & Living', 'ốc vít, vặn vít', 'Một thiết bị có chức năng xoắn ốc.', 'con vít bộ xương (Caprella); con vít cát'),
    ('68223037-a36e-5762-839e-002e13a8bd4f', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'shatter', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ˈʃæt.ə(ɹ)/', 'audio/shatter.mp3', 'A fragment of anything shattered.', 'to break a glass into shatters', 'Home & Living', 'làm vỡ tan', 'Một mảnh vỡ của bất cứ thứ gì bị đập vỡ.', 'làm vỡ một cái ly thành những mảnh vụn'),
    ('8cc445b6-f37a-55b7-8c19-25bd0555c9b8', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'shed', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/ʃɛd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shed-us.mp3', 'To part, separate or divide.', 'A metal comb shed her golden hair.', 'Home & Living', 'rụng, tỏa ra', 'Để tách ra, phân chia hoặc chia ra.', 'Một chiếc lược kim loại làm rụng mái tóc vàng của cô ấy.'),
    ('f8fd2507-c395-5bc3-9f04-6d0c27019d61', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'situated', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈsɪt͡ʃueɪtɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/situated-us.mp3', 'To place on or into a physical location.', 'The statue is situated in a corner hardly visible to the public, except through a window from an outside maintenance area situated behind the building.', 'Home & Living', 'được đặt ở', 'Để đặt vào hoặc vào một vị trí vật lý.', 'Bức tượng được đặt ở một góc hầu như không thể nhìn thấy được đối với công chúng, ngoại trừ qua một cửa sổ từ một khu vực bảo trì bên ngoài nằm phía sau tòa nhà.'),
    ('e0dbb1cc-b6f4-5144-8f02-8782c50d114c', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'slot', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/slɒt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/slot-us.mp3', 'A broad, flat, wooden bar, a slat, especially as used to secure a door, window, etc.', 'to slot a door', 'Home & Living', 'khe, rãnh', 'Một thanh gỗ rộng, phẳng, đặc biệt được dùng để cố định cửa, cửa sổ, v.v.', 'đóng then cửa'),
