    ('12147698-f923-5f85-9384-212d090e7c26', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'wipe', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, '/waɪp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wipe-us.mp3', 'The act of wiping something.', 'multiple wipes of a computer''s hard disk', 'Home & Living', 'lau chùi', 'Hành động lau chùi thứ gì đó.', 'nhiều lần xóa dữ liệu ổ cứng máy tính'),
    ('de8b5c5f-d477-57f0-8764-6f08eda19faf', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'residential', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, NULL, 'audio/residential.mp3', 'A trip during which people temporarily live together.', 'The youth group organises annual residentials.', 'Home & Living', 'dân cư, khu ở', 'Một chuyến đi mà trong đó mọi người tạm thời sống cùng nhau.', 'Nhóm thanh niên tổ chức các chuyến đi ở tập trung hàng năm.'),
