    ('2b55aa02-a1f7-59d4-bbdf-5e0644da9f3c', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'removal', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ɹəˈmuːvəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/removal-au.mp3', 'The process of moving, or the fact of being removed.', NULL, 'Home & Living', 'sự di dời', 'Quá trình di chuyển, hoặc việc bị loại bỏ.', NULL),
