    ('1e58ea40-9fab-5b88-bade-d750a6aecc45', '4211a030-9d42-5bc6-a7c6-ca87227ccc0e', 'threshold', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈθɹeʃ(h)əʊld/', 'audio/threshold.mp3', 'The bottom-most part of a doorway that one crosses to enter; a sill.', NULL, 'Home & Living', 'ngưỡng cửa', 'Phần dưới cùng nhất của một ô cửa mà người ta bước qua để vào; một cái ngưỡng.', NULL),
