    ('b8cae966-a7ee-585b-890b-24e6bd20b8f7', 'b012a127-3099-5e50-969b-a2302efa7d86', 'admission', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ædˈmɪʃ.ən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/admission-uk.mp3', 'The act or practice of admitting.', 'I request admission for two adults', 'Education & Learning', 'sự nhận vào', 'Hành động hoặc thực hành nhận vào.', 'Tôi yêu cầu được nhận vào cho hai người lớn'),
