    ('c968f885-a693-587e-855f-9c6f2b0a93c4', 'b012a127-3099-5e50-969b-a2302efa7d86', 'philosopher', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/fɪˈlɒs.ə.fə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/philosopher-uk.mp3', 'A lover of wisdom.', NULL, 'Education & Learning', 'triết gia', 'Người yêu thích trí tuệ.', NULL),
    ('8de2e623-3a66-5c17-afca-e0d189345a91', 'b012a127-3099-5e50-969b-a2302efa7d86', 'philosophical', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˌfɪləˈsɒfɪkl̩/', 'audio/philosophical.mp3', 'Of, or pertaining to, philosophy.', NULL, 'Education & Learning', 'mang tính triết học', 'Thuộc về hoặc liên quan đến triết học.', NULL),
    ('d3237985-71b7-5ebc-b463-3a33756bea1f', 'b012a127-3099-5e50-969b-a2302efa7d86', 'scrutiny', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈskɹuː.tɪ.ni/', 'https://api.dictionaryapi.dev/media/pronunciations/en/scrutiny-uk.mp3', 'Intense study of someone or something.', NULL, 'Education & Learning', 'sự xem xét kỹ lưỡng', 'Sự nghiên cứu chuyên sâu về ai đó hoặc điều gì đó.', NULL),
    ('5336f68a-291b-51b6-ae80-bb71365cf18c', 'b012a127-3099-5e50-969b-a2302efa7d86', 'formulate', 'C1', '["v"]'::jsonb, '[{"pos": "v", "level": "C1"}]'::jsonb, NULL, 'audio/formulate.mp3', 'To reduce to, or express in, a formula; to put in a clear and definite form of statement or expression.', NULL, 'Education & Learning', 'xây dựng', 'Rút gọn thành, hoặc diễn đạt bằng, một công thức; đặt vào một hình thức phát biểu hoặc diễn đạt rõ ràng và xác định.', NULL),
    ('689439a0-3011-5a22-a609-8027f506ed4c', 'b012a127-3099-5e50-969b-a2302efa7d86', 'substitution', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, NULL, 'audio/substitution.mp3', 'The act of substituting or the state of being substituted.', NULL, 'Education & Learning', 'sự thay thế', 'Hành động thay thế hoặc trạng thái được thay thế.', NULL),
    ('3c15748e-a392-5e4c-a668-c8dd18a9e939', 'b012a127-3099-5e50-969b-a2302efa7d86', 'thought-provoking', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, NULL, 'audio/thought-provoking.mp3', 'Interesting in a way that challenges one''s beliefs, attitudes, or perspective.', NULL, 'Education & Learning', 'kích thích tư duy', 'Thú vị theo cách thách thức niềm tin, thái độ hoặc quan điểm của một người.', NULL)
