    ('fc2660be-ba22-5d6a-a7f9-bc77993f6329', '8ef643e7-8cf4-5a81-a6f2-8b9910a66dee', 'interim', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/ˈɪntəɹɪm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/interim-us.mp3', 'A transitional or temporary period between other events.', 'His car is in the shop, but they gave him a rental to drive in the interim.', 'Time & Daily Routine', 'tạm thời', 'Một giai đoạn chuyển tiếp hoặc tạm thời giữa các sự kiện khác.', 'Xe của anh ấy đang ở trong tiệm sửa, nhưng họ đã cho anh ấy một chiếc xe thuê để lái trong thời gian tạm thời.'),
    ('ceff2549-b01a-5e22-95c6-72469afc00c7', '8ef643e7-8cf4-5a81-a6f2-8b9910a66dee', 'meantime', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/ˈmiːntaɪm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/meantime-us.mp3', 'The time spent waiting for another event; time in between.', 'I''ll get started tomorrow but, in the meantime, let''s see if we can get a few more opinions.', 'Time & Daily Routine', 'trong lúc đó', 'Khoảng thời gian chờ đợi một sự kiện khác; thời gian ở giữa.', 'Tôi sẽ bắt đầu vào ngày mai nhưng, trong lúc đó, hãy xem liệu chúng ta có thể nhận thêm một vài ý kiến không.'),
    ('e3fd2715-35a3-5924-a73d-6577c7873b9a', '8ef643e7-8cf4-5a81-a6f2-8b9910a66dee', 'noon', 'C1', '["n"]'::jsonb, '[{"pos": "n", "level": "C1"}]'::jsonb, '/nuːn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/noon-uk.mp3', 'The ninth hour of the day counted from sunrise; around three o''clock in the afternoon.', '1885, When night was at its noon I heard a voice chanting the Koran in sweetest accents — Sir Richard Burton, The Book of the Thousand Nights and One Night, Night 17:', 'Time & Daily Routine', 'buổi trưa', 'Giờ thứ chín trong ngày tính từ lúc mặt trời mọc; khoảng ba giờ chiều.', '1885, Khi đêm đã về khuya, tôi nghe thấy một giọng nói tụng kinh Koran bằng những âm điệu ngọt ngào nhất — Sir Richard Burton, The Book of the Thousand Nights and One Night, Đêm 17:'),
    ('23e4a53a-a573-558e-a011-8576616d07ce', '8ef643e7-8cf4-5a81-a6f2-8b9910a66dee', 'occasional', 'C1', '["adj"]'::jsonb, '[{"pos": "adj", "level": "C1"}]'::jsonb, '/əˈkeɪʒ(ə)nəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/occasional-us.mp3', 'A person who does something only occasionally.', 'He took an occasional glass of wine.', 'Time & Daily Routine', 'thỉnh thoảng', 'Một người chỉ làm điều gì đó thỉnh thoảng.', 'Anh ấy thỉnh thoảng uống một ly rượu vang.'),
